prompt --application/shared_components/navigation/lists/custom_navigation
begin
wwv_flow_imp_shared.create_list(
 p_id=>wwv_flow_imp.id(71637811588025522)
,p_name=>'Custom Navigation'
,p_list_type=>'SQL_QUERY'
,p_list_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'Select',
'   Level       As  lvl',
'  ,menu_name (A.vc_menu_code,''N'') As label',
'  ,''f?p=&APP_ID.:''||menu_name (A.vc_menu_code,''T'')||'':&SESSION.::::''  As target',
'  ,null is_current_list_entry',
' ,menu_name (A.vc_menu_code,''I'') as imagevalue',
'  ,null  image_attribute',
'  ,null  image_alt_attribute',
'  ,null as attr1',
'  ,null',
'From MST_MENU_BASKET A,MST_MODULE_MENU B',
'WHERE A.VC_MENU_CODE = B.VC_MENU_CODE',
'AND VC_COMP_CODE=:GLOBAL_COMP_CODE',
'AND VC_ROLE_CODE=:GLOBAL_ROLE_CODE',
'and  b.ch_active = ''Y''',
'AND A.VC_MENU_CODE NOT like ''080%''',
'AND A.VC_MENU_CODE NOT like ''190%''',
'Connect By Prior A.vc_menu_code = substr(A.vc_menu_code,1,length(A.vc_menu_code)-2) AND vc_role_code=:GLOBAL_ROLE_CODE and vc_comp_code=:GLOBAL_COMP_CODE',
'Start With substr(A.vc_menu_code,1,length(A.vc_menu_code)-2) is null and vc_role_code=:GLOBAL_ROLE_CODE and vc_comp_code=:GLOBAL_COMP_CODE ',
'order by NU_SR_NO'))
,p_list_status=>'PUBLIC'
);
end;
