prompt --application/shared_components/navigation/lists/master_setup
begin
wwv_flow_imp_shared.create_list(
 p_id=>wwv_flow_imp.id(314952051904200607)
,p_name=>'Master Setup'
,p_list_type=>'SQL_QUERY'
,p_list_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT null as level_value, ',
'  A.VC_MENU_NAME as label_value, ',
'    ''f?p=&APP_ID.:''||A.VC_MENU_TARGET ||'':&SESSION.::::'' as target_value, ',
'',
'  ''YES'' as is_current, ',
'  ''width="40" height="40"'' image_attribute, ',
'  --TITLE as image_alt_attribute,',
'    '''' as attribute1,',
'    '''' as attribute2,',
'   ''<img src="'' || a.vc_logo || ''"/>'' as image_value,',
'    NULL as attribute3    ',
'    from MST_MODULE_MENU A,MST_MENU_BASKET B',
'WHERE A.VC_MENU_CODE = B.VC_MENU_CODE',
'AND B.VC_COMP_CODE=:GLOBAL_COMP_CODE',
'AND B.VC_ROLE_CODE=:GLOBAL_ROLE_CODE',
'start with A.VC_MENU_CODE like ''080%''',
'connect by prior A.VC_MENU_CODE = A.VC_MODULE_CODE'))
,p_list_status=>'PUBLIC'
);
end;
