,p_lov_name=>'LOV_COMPANY'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select vc_company_name d,vc_comp_code r ',
'from mst_company ',
'where vc_comp_Code  in (select vc_ACCESS_comp_Code ',
'                        from mst_role_comp ',
'                        where vc_user_Code IN (select DISTINCT vc_user_code ',
'                                            from mst_user ',
'                                            where upper(VC_LOGIN_NAME)=upper(:P20_USERNAME)',
'                                            and (VC_PASSWORD)=:P20_PASSWORD',
'                                            ) )'))
,p_source_type=>'LEGACY_SQL'
,p_location=>'LOCAL'
);
