,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'------------CREATE BY Kunal Agarwal-------------',
'SELECT ',
'       VC_INVOICE_NO,',
'       DT_INVOICE_DATE,',
'       VC_PO_NO,',
'       DT_PO_DATE,',
'       VC_VENDOR_GSTIN,',
'       NU_VENDOR_CODE,',
'       VC_SHIP_TO,',
'    --    SHIP_TO,',
'    --    VEHICLE_NO,',
'         CASE ',
'       WHEN (NVL(NU_GST1_AMOUNT, 0) != 0 OR NVL(NU_GST2_AMOUNT, 0) != 0)',
'           THEN NVL(NU_GST1_AMOUNT, 0) + NVL(NU_GST2_AMOUNT, 0)',
'       ELSE NVL(NU_GST1_AMOUNT, 0) + NVL(NU_GST2_AMOUNT, 0) + NVL(NU_GST3_AMOUNT, 0)',
'   END  AS TAX_AMOUNT,',
'       NU_TOTAL_AMOUNT AS INVOICE_AMOUNT,',
'      initcap(VC_VENDOR_NAME),',
'    --    NU_VENDOR_CODE,',
'    --    CH_STATUS,',
'    --    CH_FAIL_STATUS,',
'    --    VC_FILE_NAME,',
'    --    PDF_DATA,',
'    --    VC_MIME_TYPE,',
'       CH_STATE_CODE,',
'       UPS_GST_IN,',
'       DT_CREATE_DATE,',
'       VC_CREATE_BY,',
'       DT_UPDATED_DATE,',
