'       NU_PACKING_CHARGES,',
'       NU_FREIGHT_CHARGES,',
'       NU_LOADING_CHARGES,',
'       NU_TCS_RECEIVABLE',
'    --    VC_DELIVERY_NO',
'  from EBIZAI.VI_HD_VENDOR_INV',
'  WHERE CH_STATUS=''P''',
'AND  VC_HOLD_REASON IS  NULL',
'--   AND CH_FAIL_STATUS=''T''',
'  AND VC_COMP_CODE=:GLOBAL_COMP_CODE',
'  '))
