'$("#P4_QUANTITY").on("keypress keyup blur", function (event) {',
'    // Allow only digits and a single decimal point, but not starting with ''-''',
'    var input = $(this).val();',
'    if (input.startsWith(''-'') || input === ''.'') {',
'        $(this).val('''');',
'        return;',
'    }',
'    ',
'    $(this).val(input.replace(/[^0-9\.]/g, ''''));',
'',
'    // Prevent entering more than one decimal point',
'    if ((event.which != 46 || $(this).val().indexOf(''.'') != -1) && ',
'        (event.which < 48 || event.which > 57)) {',
'        event.preventDefault();',
'    }',
'',
'    var text = $(this).val();',
'    // Restrict to 4 digits after the decimal',
'    if ((text.indexOf(''.'') != -1) &&',
'        (text.substring(text.indexOf(''.'')).length > 4) &&',
'        (event.which != 0 && event.which != 8) &&',
'        ($(this)[0].selectionStart >= text.length - 4)) {',
'        event.preventDefault();',
'    }',
'',
'    // Prevent leading zeroes (e.g., 01 or -0)',
'    if (text.length > 1 && text.startsWith(''0'') && text[1] !== ''.'') {',
'        $(this).val(text.substring(1));',
'    }',
'});',
'////',
'',
'function js_del_menu(v_seq) {',
'    // Set the message in the dialog',
'    document.getElementById(''confirmMessage'').innerText = "Are you sure you want to delete the row no: " + v_seq +  "?";',
'    ',
'    // Show the dialog and overlay',
'    document.getElementById(''customConfirm'').style.display = ''block'';',
'    document.getElementById(''overlay'').style.display = ''block'';',
'',
'    // Handle the OK button click',
'    document.getElementById(''confirmOk'').onclick = function() {',
'        // Hide the dialog',
'        document.getElementById(''customConfirm'').style.display = ''none'';',
'        document.getElementById(''overlay'').style.display = ''none'';',
'',
'        // Call the server process to delete the task',
'        apex.server.process("DELETE_MENU", {',
'            pageItems: "",',
'            x01: v_seq',
'        }, {',
'            type: ''GET'',',
'            dataType: ''text'',',
'            success: function(data) {',
'                apex.region("report").refresh(); ',
'              ///  apex.region("COURSE_DETAILS").refresh();  ',
'            }',
'        });',
'    };',
'',
'    // Handle the Cancel button click',
'    document.getElementById(''confirmCancel'').onclick = function() {',
'        // Hide the dialog and overlay',
'        document.getElementById(''customConfirm'').style.display = ''none'';',
'        document.getElementById(''overlay'').style.display = ''none'';',
'    };',
'}'))
