,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'-- DECLARE',
'--     l_path      VARCHAR2(100);',
'--     l_ID        NUMBER;',
'--     l_file_ext  VARCHAR2(100);',
'--     l_count     NUMBER;',
'-- BEGIN',
'--     -- Check if a record exists in hd_supp_quote_temp for the given supplier and quote number',
'--  SELECT COUNT(*)',
'--     INTO l_count',
'--     FROM ebizai.VI_HD_VENDOR_INV',
'--     WHERE VC_INVOICE_NO = :P4_VC_INVOICE_NUMBER',
'--     --   AND VC_VENDOR_NAME = :P4_VC_VENDOR_NAME;',
'--     AND DT_INVOICE_DATE=to_date(:P4_INVOICE_DATE,''MM-DD-YY'')',
'--      AND NU_VENDOR_CODE =:P4_VC_VENDOR_NAME',
'--      AND VC_COMP_CODE=:GLOBAL_COMP_CODE;',
'--     -- If the count is greater than 0, proceed with fetching the file name and processing',
'--     IF l_count > 0 THEN',
'--         -- Retrieve the file path from hd_supp_quote_temp',
'--         SELECT vc_file_name INTO l_path',
'--         FROM ebizai.VI_HD_VENDOR_INV',
'--         WHERE VC_INVOICE_NO = :P4_VC_INVOICE_NUMBER',
'--         AND DT_INVOICE_DATE=to_date(:P4_INVOICE_DATE,''MM-DD-YY'')',
'--      AND NU_VENDOR_CODE =:P4_VC_VENDOR_NAME',
'--      AND VC_COMP_CODE=:GLOBAL_COMP_CODE;',
'',
'',
'--         -- Extract the file extension',
'--         l_file_ext := SUBSTR(l_path, INSTR(l_path, ''.'', -1, 1) + 1);',
'',
'--         -- If the file is a PDF, embed it; otherwise, provide a download link and image',
'--         IF UPPER(l_file_ext) = ''PDF'' THEN',
'--             htp.p(''<embed src="https://4.213.50.111:8443/ords/wsts/INVOICE/PDF?id='' || :P4_VC_INVOICE_NUMBER || ',
'--                    ''&qid='' || :P4_VC_VENDOR_NAME ||''&cd='' || :GLOBAL_COMP_CODE ||''&dt='' || :P4_INVOICE_DATE || ''" width="600px" height="800px" />'');',
'--         ELSE',
'--             -- For non-PDF files, provide a download link and show the image',
'--             htp.p(''<a href="https://4.213.50.111:8443/ords/wsts/img/pdf?id='' || :P4_VC_INVOICE_NUMBER || ',
'--                   ''&qid='' || :P4_VC_VENDOR_NAME ||''&cd='' || :GLOBAL_COMP_CODE ||''&dt='' || :P4_INVOICE_DATE || ''" download="downloaded_image">Download Image</a>'');',
'',
'--             htp.p(''<img src=https://4.213.50.111:8443/ords/wsts/img/pdf?id='' || :P4_VC_INVOICE_NUMBER || ',
'--                    ''&qid='' || :P4_VC_VENDOR_NAME ||''&cd='' || :GLOBAL_COMP_CODE ||''&dt='' || :P4_INVOICE_DATE || ''" width="100%"/>'');',
'--         END IF;',
'',
'--     ELSE',
'--         -- Handle case when no records found (optional: could raise an error or do nothing)',
'--         htp.p(''No record found for the given Vendor Name and Invoice  Number.'');',
'--     END IF;',
'',
'-- END;',
'',
'--------------new code------------------------------------',
'DECLARE',
'    l_path      VARCHAR2(100);',
'    l_ID        NUMBER;',
'    l_file_ext  VARCHAR2(100);',
'    l_count     NUMBER;',
'BEGIN',
'    -- Check if a record exists in hd_supp_quote_temp for the given supplier and quote number',
' SELECT COUNT(*)',
'    INTO l_count',
'    FROM ebizai.VI_HD_VENDOR_INV',
'    WHERE NU_LOG_ID=:P4_NU_LOG_ID;',
'    -- VC_INVOICE_NO = :P4_VC_INVOICE_NUMBER',
'    -- --   AND VC_VENDOR_NAME = :P4_VC_VENDOR_NAME;',
'    -- AND DT_INVOICE_DATE=to_date(:P4_INVOICE_DATE,''MM-DD-YY'')',
'    --  AND NU_VENDOR_CODE =:P4_VC_VENDOR_NAME',
'    --  AND VC_COMP_CODE=:GLOBAL_COMP_CODE;',
'    -- If the count is greater than 0, proceed with fetching the file name and processing',
'    IF l_count > 0 THEN',
'        -- Retrieve the file path from hd_supp_quote_temp',
'        SELECT vc_file_name INTO l_path',
'        FROM ebizai.VI_HD_VENDOR_INV',
'        WHERE NU_LOG_ID=:P4_NU_LOG_ID;',
'    --     VC_INVOICE_NO = :P4_VC_INVOICE_NUMBER',
'    --     AND DT_INVOICE_DATE=to_date(:P4_INVOICE_DATE,''MM-DD-YY'')',
'    --  AND NU_VENDOR_CODE =:P4_VC_VENDOR_NAME',
'    --  AND VC_COMP_CODE=:GLOBAL_COMP_CODE;',
'',
'',
'        -- Extract the file extension',
'        l_file_ext := SUBSTR(l_path, INSTR(l_path, ''.'', -1, 1) + 1);',
'',
'        -- If the file is a PDF, embed it; otherwise, provide a download link and image',
'        IF UPPER(l_file_ext) = ''PDF'' THEN',
'            htp.p(''<embed src="https://4.213.96.201:8443/ords/wsts/IMG/PDF?ID='' || :P4_NU_LOG_ID || ',
'                 ''" width="600px" height="800px" />'');',
'        ELSE',
'            -- For non-PDF files, provide a download link and show the image',
'            htp.p(''<a href="https://4.213.96.201:8443/ords/wsts/IMG/PDF?ID='' || :P4_NU_LOG_ID || ',
'                  ''" download="downloaded_image">Download Image</a>'');',
'',
'            htp.p(''<img src=https://4.213.96.201:8443/ords/wsts/IMG/PDF?ID='' || :P4_NU_LOG_ID || ',
'                    ''" width="100%"/>'');',
'        END IF;',
'',
'    ELSE',
'        -- Handle case when no records found (optional: could raise an error or do nothing)',
'        htp.p(''No record found for the given Vendor Name and Invoice  Number.'');',
'    END IF;',
'',
'END;',
'',
'',
