'---------------CREATE BY kUNAL Agarwal----------',
'',
'SELECT ',
'   SEQ_ID AS SEQ_ID,',
'   C001 AS ITEM_DESC,       -- Item Description',
'--    C002 AS ITEM_CODE,',
'   C005 AS SAP_item_code,       -- Item Code',
'   C003 AS HSN_CODE,        -- HSN Code',
'   C004 AS UOM,             -- Unit of Measure',
'   N003 AS "INVOICE QUANTITY",',
'--    C008 AS "INVOICE QUANTITY",        -- Quantity',
'   N004 AS "INVOICE RATE"  ,  ',
'   C011 AS LINE_NUMBER, -- Rate',
'   C010 AS PO_NUMBER,',
'   D001 AS PO_DATE,',
'--    N005 AS AMOUNT,',
'--    NVL(C009, 0) AS "DISCOUNT%",',
' --  N002 AS PI_LOGID,',
'  ''EDIT'' AS EDIT,',
'',
'   C012 AS STATUS,',
'    ''<div class="del_menu" onclick=js_del_menu('''''' || SEQ_ID || '''''')>',
'            <i class="fa fa-trash u-danger-text ebiz-del-task" aria-hidden="true"></i>',
'        </div>'' AS Delete_Button ,',
'',
'     N001 AS "PO RATE",',
'   N002 AS "AVAILABLE PO QTY",',
'   C013      AS "HEAT NO",',
'   C014     AS    "MILL NAME",',
'C015       AS     "MILL COUNTRY"  ,',
'C016      AS   "STORAGE LOCATION" ',
'  ',
'--   C008 AS Actual_Qty',
'  ',
'FROM APEX_COLLECTIONS ',
'WHERE COLLECTION_NAME = ''VENDOR_DT''',
'AND C050 = :GLOBAL_DOC_NO',
'',
'',
'',
'',
'',
''))
,p_plug_source_type=>'NATIVE_JQM_REFLOW'
,p_attribute_01=>'STRIPE:STROKE'
);
