wwv_flow_imp_page.create_page_validation(
 p_id=>wwv_flow_imp.id(315219499346072554)
,p_validation_name=>'checking_qty_rate'
,p_validation_sequence=>30
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'------------------------Developed by Kunal Agarwal ---------------------------------------------',
'---------last updated on 04/04/2025----------------------------------------------------------',
'',
'',
'DECLARE',
'    -- Variables to hold fetched data',
'    V_QTY   NUMBER;',
'    V_RATE  NUMBER;',
'    V_COUNT NUMBER;',
'     V_ERROR_MSG VARCHAR2(500);',
'     V_ERROR_MSG_1 VARCHAR2(500);',
'     v_tax_rate number;',
'     v_invoice_total number;',
'',
'',
'    -- Cursor to loop through the collection',
'    CURSOR C IS',
'        SELECT ',
'            C005 AS SAP_ITEM_CODE,  -- SAP Item Cod    -- Vendor Code',
'            N003 AS ACTUAL_QTY,     -- Actual Quantity',
'            N004 AS RATE   ,',
'            C011 AS LINE_NUMBER ,   -- Rate',
'            C010 AS PO_NUMBER   ,',
'            D001 AS PO_DATE   ',
'        FROM APEX_COLLECTIONS ',
'        WHERE COLLECTION_NAME = ''VENDOR_DT'';',
'',
'BEGIN',
'    -- Loop through each record in the collection',
'    FOR I IN C LOOP',
'    DBMS_OUTPUT.PUT_LINE(''Processing SAP_ITEM_CODE: '' || NVL(I.SAP_ITEM_CODE, ''NULL''));',
'',
'    -- V_COUNT:=NULL;',
'',
'    IF I.SAP_ITEM_CODE IS NULL THEN',
'     return ''Please Map all the items'';',
'     EXIT; ',
'',
'    END IF; ',
'',
'        -- Check if the item code exists in the specified PO',
'        SELECT COUNT(*)',
'        INTO V_COUNT',
'        -- FROM EBIZAI.SAP_PENDING_PO_TBL',
'        from EBIZAI.vw_sap_pending_po_vendor_gst',
'        WHERE VC_PO_NUMBER = I.PO_NUMBER',
'          AND VC_ITEM_CODE = I.SAP_ITEM_CODE',
'         ',
'          AND VC_LINE_NUMBER=I.LINE_NUMBER',
'        --   AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'        and vc_gst_no=:P4_VENDOR_GST_IN',
'        ',
'          ;',
'          ',
'',
'        IF V_COUNT = 0 THEN',
'        V_ERROR_MSG_1:=''Item Code''|| I.SAP_ITEM_CODE||''Not found in purchase order'';',
'        RETURN V_ERROR_MSG_1;',
' ',
'            -- CONTINUE; -- Skip to the next iteration',
'        END IF;',
'',
'        -- Fetch quantity and rate for the item',
'        BEGIN',
'       SELECT ',
'  (',
'    "Still to be delivered (qty)" - ',
'    NVL((',
'      SELECT B.NU_QUANTITY',
'FROM HD_INVOICE_APP A, DT_INVOICE_APP B',
'WHERE A.NU_LOG_ID=B.NU_PI_LOGID',
'AND B.VC_PO_NUMBER=I.PO_NUMBER',
'AND TRIM(B.VC_SAP_ITEM_CODE) = TRIM(I.SAP_ITEM_CODE)',
'AND B.VC_LINE_NUMBER= I.LINE_NUMBER',
'AND A.VC_MIGO_STATUS=''P''',
'    ), 0)',
'  ) AS ADJUSTED_DELIVERY_QTY,',
'  ROUND(',
'    CASE ',
'      WHEN "Purchasing Doc. Type" IN (''ZSCO'', ''ZSFG'') THEN Document_Total_Net_Price',
'      ELSE ',
'        TO_NUMBER("Net Price") / ',
'        CASE ',
'          WHEN NVL(TO_NUMBER("Price unit"), 0) = 0 THEN 1 ',
'          ELSE TO_NUMBER("Price unit") ',
'        END ',
'    END, ',
'    4',
'  )',
'INTO V_QTY,V_RATE',
'FROM EBIZAI.VW_PURCHASE_DOC_TOTALS',
'WHERE "Purchasing Document" = NVL(I.PO_NUMBER, ''***'')',
'  AND TRIM("Material") = TRIM(I.SAP_ITEM_CODE)',
'  AND "Item" = I.LINE_NUMBER;',
'            -- Validate quantity and rate',
'            IF V_QTY < I.ACTUAL_QTY OR V_RATE != I.RATE THEN',
'            V_ERROR_MSG := ''Item code '' || :P4_SAP_ITEM_CODE1|| '' RATE OR QTY MISMATCH'';',
'             RETURN V_ERROR_MSG;',
'            -- CONTINUE; -- Skip to the next iteration',
'            END IF;',
'        EXCEPTION',
'            WHEN NO_DATA_FOUND THEN NULL;',
'                 --RETURN''No existing record found for Item Code:  . Proceeding with insertion.'';',
'        END;',
'',
'        -- Proceed with insertion logic here',
'        --  RETURN''Validation successful for Item Code:. Proceeding with insertion.'';',
'    END LOOP;',
'',
'',
'    -- Commit the transaction if needed',
'    COMMIT;',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        ROLLBACK;',
'        RAISE;',
'END;'))
,p_validation2=>'PLSQL'
,p_validation_type=>'FUNC_BODY_RETURNING_ERR_TEXT'
,p_validation_condition_type=>'NEVER'
,p_when_button_pressed=>wwv_flow_imp.id(314291730848633879)
,p_error_display_location=>'INLINE_WITH_FIELD_AND_NOTIFICATION'
);
end;
/
begin
wwv_flow_imp_page.create_page_validation(
 p_id=>wwv_flow_imp.id(8625118922428561)
,p_validation_name=>'checking_qty_rate_1'
,p_validation_sequence=>40
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    V_QTY           NUMBER;',
'    V_RATE          NUMBER;',
'    V_COUNT         NUMBER;',
'    V_ERROR_MSG     VARCHAR2(500);',
'    V_ERROR_MSG_1   VARCHAR2(500);',
'    V_TAX_RATE      NUMBER;',
'    V_INVOICE_TOTAL NUMBER;',
'    V_COMPUTED_TOTAL NUMBER := 0;',
'    V_ITEM_TOTAL    NUMBER;',
'    CURSOR C IS',
'        SELECT ',
'            C005 AS SAP_ITEM_CODE,',
'            N003 AS ACTUAL_QTY,',
'            N004 AS RATE,',
'            C011 AS LINE_NUMBER,',
'            C010 AS PO_NUMBER,',
'            D001 AS PO_DATE,',
'            C016 AS STORAGE_LOCATION',
'        FROM APEX_COLLECTIONS ',
'        WHERE COLLECTION_NAME = ''VENDOR_DT'';',
'BEGIN',
'    -- Loop through collection',
'    FOR I IN C LOOP',
'        DBMS_OUTPUT.PUT_LINE(''Processing SAP_ITEM_CODE: '' || NVL(I.SAP_ITEM_CODE, ''NULL''));',
'        IF I.SAP_ITEM_CODE IS NULL THEN',
'            RETURN ''Please map all the items'';',
'            EXIT;',
'        END IF;',
' -- Validate item in PO',
'        SELECT COUNT(*)',
'        INTO V_COUNT',
'        FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'        WHERE VC_PO_NUMBER = I.PO_NUMBER',
'          AND VC_ITEM_CODE = I.SAP_ITEM_CODE',
'          AND VC_LINE_NUMBER = I.LINE_NUMBER',
'          AND vc_gst_no = :P4_VENDOR_GST_IN;',
'',
'        IF V_COUNT = 0 THEN',
'            RETURN ''Item Code '' || I.SAP_ITEM_CODE || '' not found in purchase order'';',
'        END IF;',
'-- Get qty and rate',
'        BEGIN',
'          SELECT ',
'  (',
'    a."Still to be delivered (qty)" - ',
'    NVL((',
'      SELECT SUM(B.NU_QUANTITY)',
'      FROM HD_INVOICE_APP A1, DT_INVOICE_APP B',
'      WHERE A1.NU_LOG_ID = B.NU_PI_LOGID',
'        AND B.VC_PO_NUMBER = I.PO_NUMBER',
'        AND TRIM(B.VC_SAP_ITEM_CODE) = TRIM(I.SAP_ITEM_CODE)',
'        AND B.VC_LINE_NUMBER = I.LINE_NUMBER',
'        AND A1.VC_MIGO_STATUS = ''P''',
'    ), 0)',
'  ) AS ADJUSTED_DELIVERY_QTY,',
'  ROUND(',
'    CASE ',
'      WHEN a."Purchasing Doc. Type" IN (''ZSCO'', ''ZSFG'') THEN Document_Total_Net_Price',
'      WHEN B.vc_vendor_name IS NOT NULL THEN TO_NUMBER(a."Net Price")',
'      ELSE ',
'        TO_NUMBER(a."Net Price") / ',
'        CASE ',
'          WHEN NVL(TO_NUMBER(a."Price unit"), 0) = 0 THEN 1 ',
'          ELSE TO_NUMBER(a."Price unit") ',
'        END ',
'    END, ',
'    2',
'  )INTO V_QTY,V_RATE',
'  FROM EBIZAI.VW_PURCHASE_DOC_TOTALS1 A ',
'LEFT JOIN RATE_EXCEPTION B ',
'  ON TRIM(SUBSTR(a."Supplier/Supplying Plant", 7)) = UPPER(B.vc_vendor_name)',
'WHERE a."Purchasing Document" = NVL(I.PO_NUMBER, ''***'')',
'  AND TRIM(a."Material") = TRIM(I.SAP_ITEM_CODE)',
'  AND a."Item" = I.LINE_NUMBER;',
'            -- Validate qty and rate',
'            IF V_QTY < I.ACTUAL_QTY OR V_RATE != I.RATE OR I.ACTUAL_QTY =0 THEN',
'                RETURN ''Item code '' || I.SAP_ITEM_CODE || '' RATE or QTY mismatch'';',
'            END IF;',
'            ',
'            IF I.STORAGE_LOCATION IS NULL THEN',
'                RETURN ''PLEASE FILL THE STORAGE LOCATION'';',
'            END IF;    ',
'            ',
'            IF I.PO_DATE>:P4_INVOICE_DATE THEN',
'                RETURN ''PLEASE CORRECT THE INVOICE_DATE'';',
'            END IF;   ',
'',
'            IF round(:P4_TAX_AMOUNT)=round(:P4_INVOICE_AMOUNT) THEN',
'                RETURN ''Please check the invoice amount and tax amount'';',
'            END IF;',
'            IF :P4_SHIP_GST_IN IN (''06AABFU6927B1ZD'') ',
'                AND (I.PO_NUMBER LIKE ''56%'' OR I.PO_NUMBER LIKE ''57%'' OR I.PO_NUMBER LIKE ''61%'' OR I.PO_NUMBER LIKE ''75%'' OR I.PO_NUMBER LIKE ''67%'') ',
'             THEN',
'              RETURN ''Bill to Party Name is wrong'';',
'            END IF;',
'            IF :P4_SHIP_GST_IN IN (''06AABCU5506B1ZU'') ',
'                AND (I.PO_NUMBER LIKE ''46%'' OR I.PO_NUMBER LIKE ''45%'' OR I.PO_NUMBER LIKE ''47%'' OR I.PO_NUMBER LIKE ''43%'' OR I.PO_NUMBER LIKE ''75%'' OR  I.PO_NUMBER LIKE ''67%'') ',
'             THEN',
'              RETURN ''Bill to Party Name is wrong'';',
'            END IF;',
'',
'            ',
'        EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
