wwv_flow_imp_page.create_page_da_action(
 p_id=>wwv_flow_imp.id(258582935483042530)
,p_event_id=>wwv_flow_imp.id(258582859287042529)
,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'    -- SELECT NU_QTY, round(NU_RATE,4)',
'    -- INTO :P4_SAP_ITEM_RATE,:P4_SAP_RATE',
'    -- FROM',
'    -- --  EBIZAI.sap_pending_po_tbl',
'    -- EBIZAI.vw_sap_pending_po_vendor_gst',
'    -- WHERE VC_PO_NUMBER = NVL(:P4_PO_NUMBER1,''***'')',
'    -- -- AND DT_PO_DATE=:P4_PO_DATE1',
'    -- AND TRIM(VC_ITEM_CODE) = TRIM(:P4_SAP_ITEM_CODE1)',
'    -- AND VC_LINE_NUMBER = :P4_LINE_NUMBER',
'    -- AND VC_COMP_CODE=:GLOBAL_COMP_CODE;',
'    -- AND NU_VENDOR_CODE=:P4_VC_VENDOR_NAME;',
'',
'--  SELECT ',
'--   (',
'--     "Still to be delivered (qty)" - ',
'--     NVL((',
'--       SELECT B.NU_QUANTITY',
'-- FROM HD_INVOICE_APP A, DT_INVOICE_APP B',
'-- WHERE A.NU_LOG_ID=B.NU_PI_LOGID',
'-- AND B.VC_PO_NUMBER=:P4_PO_NUMBER1',
'-- AND TRIM(B.VC_SAP_ITEM_CODE) = TRIM(:P4_SAP_ITEM_CODE1)',
'-- AND B.VC_LINE_NUMBER=:P4_LINE_NUMBER',
'-- AND A.VC_MIGO_STATUS=''P''',
'--     ), 0)',
'--   ) AS ADJUSTED_DELIVERY_QTY,',
'--   ROUND(',
'--     CASE ',
'--       WHEN "Purchasing Doc. Type" IN (''ZSCO'', ''ZSFG'') THEN Document_Total_Net_Price',
'--       ELSE ',
'--         TO_NUMBER("Net Price") / ',
'--         CASE ',
'--           WHEN NVL(TO_NUMBER("Price unit"), 0) = 0 THEN 1 ',
'--           ELSE TO_NUMBER("Price unit") ',
'--         END ',
'--     END, ',
'--     2',
'--   )',
'-- INTO :P4_SAP_ITEM_RATE, :P4_SAP_RATE',
'-- FROM EBIZAI.VW_PURCHASE_DOC_TOTALS',
'-- WHERE "Purchasing Document" = NVL(:P4_PO_NUMBER1, ''***'')',
'--   AND TRIM("Material") = TRIM(:P4_SAP_ITEM_CODE1)',
'--   AND "Item" = :P4_LINE_NUMBER;',
'SELECT ',
'  (',
'    a."Still to be delivered (qty)" - ',
'    NVL((',
'      SELECT SUM(B.NU_QUANTITY)',
'      FROM HD_INVOICE_APP A1, DT_INVOICE_APP B',
'      WHERE A1.NU_LOG_ID = B.NU_PI_LOGID',
'        AND B.VC_PO_NUMBER = :P4_PO_NUMBER1',
'        AND TRIM(B.VC_SAP_ITEM_CODE) = TRIM(:P4_SAP_ITEM_CODE1)',
'        AND B.VC_LINE_NUMBER = :P4_LINE_NUMBER',
'        AND A1.VC_MIGO_STATUS = ''P''',
'    ), 0)',
'  ) AS ADJUSTED_DELIVERY_QTY,',
'  ROUND(',
'    CASE ',
'      WHEN a."Purchasing Doc. Type" IN (''ZSCO'', ''ZSFG'') THEN Document_Total_Net_Price',
'      WHEN B.vc_vendor_name IS NOT NULL THEN TO_NUMBER(a."Net Price")',
'      ELSE ',
'        TO_NUMBER(a."Net Price") / ',
'        CASE ',
'          WHEN NVL(TO_NUMBER(a."Price unit"), 0) = 0 THEN 1 ',
'          ELSE TO_NUMBER(a."Price unit") ',
'        END ',
'    END, ',
'    2',
'  ),A."Storage location"',
'  INTO :P4_SAP_ITEM_RATE,:P4_SAP_RATE,:P4_VC_STORAGE_LOCATION',
'  ',
'FROM EBIZAI.VW_PURCHASE_DOC_TOTALS1 A ',
'LEFT JOIN RATE_EXCEPTION B ',
'  ON TRIM(SUBSTR(a."Supplier/Supplying Plant", 7)) = UPPER(B.vc_vendor_name)',
'WHERE a."Purchasing Document" = NVL(:P4_PO_NUMBER1, ''***'')',
'  AND TRIM(a."Material") = TRIM(:P4_SAP_ITEM_CODE1)',
'  AND a."Item" = :P4_LINE_NUMBER;',
'--   and "Purchasing Doc. Type" in (''ZSCO'',''ZSFG'');',
'',
'    -- You can use the retrieved values here',
'    -- DBMS_OUTPUT.PUT_LINE(''Quantity: '' || v_nu_qty || '', Rate: '' || v_nu_rate);',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        DBMS_OUTPUT.PUT_LINE(''No records found.'');',
'    WHEN TOO_MANY_ROWS THEN',
'        DBMS_OUTPUT.PUT_LINE(''Multiple records found. Expected only one.'');',
'    WHEN OTHERS THEN',
'        DBMS_OUTPUT.PUT_LINE(''Error: '' || SQLERRM);',
'END;',
'',
''))
,p_attribute_02=>'P4_PO_NUMBER1,P4_SAP_ITEM_CODE1,P4_LINE_NUMBER'
,p_attribute_03=>'P4_SAP_ITEM_RATE,P4_SAP_RATE,P4_VC_STORAGE_LOCATION'
,p_attribute_04=>'N'
,p_attribute_05=>'PLSQL'
,p_wait_for_result=>'Y'
);
