wwv_flow_imp_page.create_page_da_action(
 p_id=>wwv_flow_imp.id(7025919642303288)
,p_event_id=>wwv_flow_imp.id(7025823743303287)
,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'-- BEGIN',
'--     SELECT distinct(dt_po_date)',
'--     INTO :P4_PO_DATE1',
'--     FROM EBIZAI.sap_pending_po_tbl',
'--     WHERE VC_PO_NUMBER = NVL(:P4_PO_NUMBER1,''***'')',
'--     -- AND DT_PO_DATE=:P4_PO_DATE1',
'--     -- AND TRIM(VC_ITEM_CODE) = TRIM(:P4_SAP_ITEM_CODE1)',
'--     -- AND VC_LINE_NUMBER = :P4_LINE_NUMBER',
'--     AND VC_COMP_CODE=:GLOBAL_COMP_CODE;',
'--     -- AND NU_VENDOR_CODE=:P4_VC_VENDOR_NAME;',
'    ',
'',
'--     -- You can use the retrieved values here',
'--     -- DBMS_OUTPUT.PUT_LINE(''Quantity: '' || v_nu_qty || '', Rate: '' || v_nu_rate);',
'-- EXCEPTION',
'--     WHEN NO_DATA_FOUND THEN',
'--         DBMS_OUTPUT.PUT_LINE(''No records found.'');',
'--     WHEN TOO_MANY_ROWS THEN',
'--         DBMS_OUTPUT.PUT_LINE(''Multiple records found. Expected only one.'');',
'--     WHEN OTHERS THEN',
'--         DBMS_OUTPUT.PUT_LINE(''Error: '' || SQLERRM);',
'-- END;',
'--------------------second code--------------------',
'---------third code--------------------------',
'DECLARE',
'    v_item_count      NUMBER;',
'    v_line_count      NUMBER;',
'    v_item_code       EBIZAI.sap_pending_po_tbl.VC_ITEM_CODE%TYPE;',
'    -- v_po_date         EBIZAI.sap_pending_po_tbl.DT_PO_DATE%TYPE;',
'    -- v_line_number     EBIZAI.sap_pending_po_tbl.VC_LINE_NUMBER%TYPE;',
'BEGIN',
'    -- Always get PO Date',
'    SELECT distinct(DT_PO_DATE)',
'    INTO :P4_PO_DATE1',
'    FROM EBIZAI.sap_pending_po_tbl',
'    WHERE VC_PO_NUMBER = NVL(:P4_PO_NUMBER1, ''***'')',
'      AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'',
'    -- :P4_PO_DATE1 := v_po_date;',
'',
'    -- Count distinct item codes',
'    SELECT COUNT(DISTINCT TRIM(VC_ITEM_CODE))',
'    INTO v_item_count',
'    FROM EBIZAI.sap_pending_po_tbl',
'    WHERE VC_PO_NUMBER = NVL(:P4_PO_NUMBER1, ''***'')',
'      AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'',
'    -- If only one item code, fetch it',
'    IF v_item_count = 1 THEN',
'        SELECT DISTINCT TRIM(VC_ITEM_CODE)',
'        INTO v_item_code',
'        FROM EBIZAI.sap_pending_po_tbl',
'        WHERE VC_PO_NUMBER = NVL(:P4_PO_NUMBER1, ''***'')',
'          AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'',
'        :P4_SAP_ITEM_CODE1 := v_item_code;',
'',
'        -- Now count distinct line numbers for this item code',
'        SELECT COUNT(DISTINCT VC_LINE_NUMBER)',
'        INTO v_line_count',
'        FROM EBIZAI.sap_pending_po_tbl',
'        WHERE VC_PO_NUMBER = NVL(:P4_PO_NUMBER1, ''***'')',
'          AND TRIM(VC_ITEM_CODE) = v_item_code',
'          AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'',
'        -- If only one line number for the item, populate it',
'        IF v_line_count = 1 THEN',
'            SELECT DISTINCT VC_LINE_NUMBER',
'            INTO :P4_LINE_NUMBER',
'            FROM EBIZAI.sap_pending_po_tbl',
'            WHERE VC_PO_NUMBER = NVL(:P4_PO_NUMBER1, ''***'')',
'              AND TRIM(VC_ITEM_CODE) = v_item_code',
'              AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'',
'            -- :P4_LINE_NUMBER := v_line_number;',
'        ELSE',
'            :P4_LINE_NUMBER := NULL;',
'            DBMS_OUTPUT.PUT_LINE(''Multiple line numbers for item code. Not populating line number.'');',
'        END IF;',
'    ELSE',
'        :P4_SAP_ITEM_CODE1 := NULL;',
'        :P4_LINE_NUMBER := NULL;',
'        DBMS_OUTPUT.PUT_LINE(''Multiple item codes. Not populating item code or line number.'');',
'    END IF;',
'',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        :P4_PO_DATE1 := NULL;',
'        :P4_SAP_ITEM_CODE1 := NULL;',
'        :P4_LINE_NUMBER := NULL;',
'        DBMS_OUTPUT.PUT_LINE(''No matching PO found.'');',
'    WHEN TOO_MANY_ROWS THEN',
'        :P4_SAP_ITEM_CODE1 := NULL;',
'        :P4_LINE_NUMBER := NULL;',
'        DBMS_OUTPUT.PUT_LINE(''Unexpected multiple rows. Check data.'');',
'    WHEN OTHERS THEN',
'        :P4_PO_DATE1 := NULL;',
'        :P4_SAP_ITEM_CODE1 := NULL;',
'        :P4_LINE_NUMBER := NULL;',
'        DBMS_OUTPUT.PUT_LINE(''Error: '' || SQLERRM);',
'END;',
'',
'',
''))
,p_attribute_02=>'P4_PO_NUMBER1'
,p_attribute_03=>'P4_PO_DATE1,P4_SAP_ITEM_CODE1,P4_LINE_NUMBER'
,p_attribute_04=>'N'
,p_attribute_05=>'PLSQL'
,p_wait_for_result=>'Y'
);
