,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_count NUMBER;',
'    v_line_number NUMBER;',
'BEGIN',
'    SELECT COUNT(*) INTO v_count',
'    FROM EBIZAI.VW_PURCHASE_DOC_TOTALS',
'     WHERE "Material" = :P4_SAP_ITEM_CODE1',
'      and "Purchasing Document"=:P4_PO_NUMBER1;',
'     ',
'',
'    IF v_count = 1 THEN',
'        -- Populate the next available line number (or start from 1)',
'        SELECT "Item" INTO :P4_LINE_NUMBER',
'        FROM EBIZAI.VW_PURCHASE_DOC_TOTALS',
'        WHERE "Material" = :P4_SAP_ITEM_CODE1',
'        and "Purchasing Document"=:P4_PO_NUMBER1;',
'',
'        -- :P4_LINE_NUMBER := v_line_number;  -- Set APEX page item with the new line number',
'    ELSE',
'        :P4_LINE_NUMBER := NULL;  -- Don''t populate if count > 1',
'    END IF;',
'END;',
''))
,p_attribute_02=>'P4_SAP_ITEM_CODE1,P4_PO_NUMBER1'
,p_attribute_03=>'P4_LINE_NUMBER'
,p_attribute_04=>'N'
,p_attribute_05=>'PLSQL'
,p_wait_for_result=>'Y'
);
