wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(315219594502072555)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'HD_DT_SAVE_NEW_1'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'------------------------Developed by Kunal Agarwal ---------------------------------------------',
'---------------------Changed on 05/04/2025 ------------------------------------------------',
'-----------------changed  in the query-------------------------------',
'',
'DECLARE',
'    -- Declare PI_LOG_ID once and initialize it',
'    V_PI_LOG_ID NUMBER := 0;',
'',
'    -- Declare variables to hold values from VI_HF_DATA_TBL',
'    VC_DELIVERY_NO VARCHAR2(500);',
'    SHIP_TO VARCHAR2(500);',
'    VEHICLE_NO VARCHAR2(500);',
'    PDF_DATA BLOB;',
'    VC_MIME_TYPE VARCHAR2(100);',
'    VC_FILE_NAME VARCHAR2(200);',
'    VC_VENDOR_NAME VARCHAR2(100);',
'    V_QTY NUMBER;',
'    V_RATE NUMBER;',
'    VC_COMP_CODE VARCHAR2(3);',
'    -- V_CGST NUMBER;',
'    -- V_SGST NUMBER;',
'    -- V_IGST NUMBER;',
'    -- V_TOTAL_AMOUNT NUMBER;',
'',
'    -- Cursor to fetch the necessary data from APEX_COLLECTIONS',
'    CURSOR C IS',
'        SELECT ',
'            C001 AS ITEM_DESC,       -- Item Description',
'            C002 AS ITEM_CODE,       -- Item Code',
'            C003 AS HSN_CODE,        -- HSN Code',
'            C004 AS UOM,             -- Unit of Measure',
'            C010 AS PO_NUMBER ,  ---PO NUMBER',
'            D001 AS PO_DATE  ,  ---- PO DATE',
'            C005 AS SAP_Item_code,   -- SAP Item Code',
'            C011 AS LINE_NUMBER,    --LINE NUMBER',
'            N003 AS QUANTITY,        -- Quantity',
'            N004 AS RATE,            -- Rate',
'            N005 AS AMOUNT,          -- Amount',
'            C009 AS DISCOUNT,        -- Discount',
'            C008 AS ACTUAL_QTY ,      -- Actual Quantity',
'            N001 AS SAP_ITEM_RATE  ,   --SAP RATE',
'            N002 AS SAP_ITEM_QTY,',
'            C013 AS HEAT_NO,        ',
'            C014 AS MILL_NAME,     ',
'            C015 AS MILL_COUNTRY,',
'            C016 AS STORAGE_LOCATION',
'            ',
'        FROM APEX_COLLECTIONS ',
'        WHERE COLLECTION_NAME = ''VENDOR_DT''',
'        AND C050 = :GLOBAL_DOC_NO;',
'BEGIN',
'    BEGIN',
'        -- Check if the invoice already exists',
'        SELECT NU_LOG_ID',
'        INTO V_PI_LOG_ID',
'        FROM EBIZAI.HD_INVOICE_APP',
'        WHERE NU_LOG_ID=:P4_NU_LOG_ID;',
'        -- VC_INVOICE_NO = :P4_VC_INVOICE_NUMBER',
'        -- AND DT_INVOICE_DATE=:P4_INVOICE_DATE',
'        --   AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'        --   AND VC_COMP_CODE=:GLOBAL_COMP_CODE;',
'',
'',
'',
'        -- If found, update the existing record',
'        UPDATE EBIZAI.HD_INVOICE_APP',
'        SET ',
'            VC_DELIVERY_NO = VC_DELIVERY_NO,',
'            VC_SHIP_TO = :P4_SHIP_TO,',
'            VC_VEHICLE_NO = VEHICLE_NO,',
'            -- VC_PDF_DATA = PDF_DATA,',
'            VC_FILE_NAME = VC_FILE_NAME,',
'            VC_MIME_TYPE = VC_MIME_TYPE,',
'            VC_VENDOR_NAME = :P4_VC_VENDOR_NAME1,',
'            VC_REMARK=:P4_VC_REMAKS,',
'            VC_HEAT_NO=:P4_VC_HEAT_NO,',
'            VC_MILL_COUNTRY=:P4_MILL_COUNTRY,',
'            VC_MILL_NAME=:P4_MILL_NAME,',
'            NU_TOTAL_TAX_AMOUNT=:P4_TAX_AMOUNT,',
'            NU_TOTAL_AMOUNT=:P4_INVOICE_AMOUNT,',
'            vc_updated_by=:SESSION_USER_NAME,',
'            dt_updated_date=SYSTIMESTAMP',
'',
'        WHERE NU_LOG_ID=:P4_NU_LOG_ID;',
'        --  VC_INVOICE_NO = :P4_VC_INVOICE_NUMBER',
'        -- AND DT_INVOICE_DATE=:P4_INVOICE_DATE',
'        --   AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'        --   AND VC_COMP_CODE=:GLOBAL_COMP_CODE;',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            -- If no existing record, insert a new one',
'            SELECT NU_LOG_ID',
'            INTO V_PI_LOG_ID',
'            FROM EBIZAI.VI_HD_VENDOR_INV',
'            WHERE NU_LOG_ID=:P4_NU_LOG_ID;',
'            --  VC_COMP_CODE=:GLOBAL_COMP_CODE;',
'',
'            ',
'        SELECT ',
'             ',
'            VC_VEHICLE_NO, ',
'            VC_PDF_DATA, ',
'            VC_MIME_TYPE, ',
'            VC_FILE_NAME',
'            -- NU_GST1_AMOUNT,',
'            -- NU_GST2_AMOUNT,',
'            -- NU_GST3_AMOUNT,',
'            -- NU_TOTAL_AMOUNT',
'        INTO ',
'            VEHICLE_NO, ',
'            PDF_DATA, ',
'            VC_MIME_TYPE, ',
'            VC_FILE_NAME',
'            -- V_CGST ,',
'            -- V_SGST, ',
'            -- V_IGST ,',
'            -- V_TOTAL_AMOUNT ',
'',
'        FROM VI_HD_VENDOR_INV',
'        WHERE NU_LOG_ID=:P4_NU_LOG_ID;',
'        -- NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'        -- AND VC_INVOICE_NO=:P4_VC_INVOICE_NUMBER',
'        -- AND DT_INVOICE_DATE=:P4_INVOICE_DATE',
'        -- AND VC_COMP_CODE=:GLOBAL_COMP_CODE;  ',
'',
'            INSERT INTO EBIZAI.HD_INVOICE_APP (',
'                VC_INVOICE_NO,',
'                DT_INVOICE_DATE,',
'                VC_PO_NO,',
'                DT_PO_DATE,',
'                VC_VENDOR_GSTIN,',
'             ',
'                NU_VENDOR_CODE,',
'          ',
'                NU_LOG_ID,',
'                VC_DELIVERY_NO,',
'                VC_SHIP_TO,',
'                VC_VEHICLE_NO,',
'                VC_INVOICE_NO1,',
'                DT_INVOICE_DATE1,',
'                VC_PDF_DATA,',
'                VC_FILE_NAME,',
'                VC_MIME_TYPE,',
'                VC_VENDOR_NAME,',
'                VC_COMP_CODE,',
'                -- VC_REMARK,',
'                VC_MILL_NAME,',
'                VC_MILL_COUNTRY,',
'                VC_HEAT_NO,',
'                UPS_GST_IN,',
'                DT_CREATE_DATE,',
'                VC_CREATE_BY,',
'                NU_TOTAL_TAX_AMOUNT,',
'                NU_TOTAL_AMOUNT,',
'                vc_migo_status,',
'                NU_PACKING_CHARGES,',
'                NU_FREIGHT_CHARGES,',
'                NU_LOADING_CHARGES,',
'                NU_TCS_RECEIVABLE',
'',
'',
'            )',
'            VALUES (',
'                :P4_VC_INVOICE_NUMBER,',
'                :P4_INVOICE_DATE,',
'                :P4_VC_P0_NUMBER,',
'                :P4_PO_DATE,',
'                :P4_VENDOR_GST_IN,',
'                ',
'                :P4_VC_VENDOR_NAME,',
'                V_PI_LOG_ID,',
'                VC_DELIVERY_NO,',
'                :P4_SHIP_TO,',
'                VEHICLE_NO,',
'                :P4_VC_INVOICE_NUMBER,',
'                :P4_INVOICE_DATE,',
'                PDF_DATA,',
'                VC_FILE_NAME,',
'                VC_MIME_TYPE,',
'                :P4_VC_VENDOR_NAME1,',
'                :GLOBAL_COMP_CODE,',
'                -- :P4_VC_REMAKS,',
'                :P4_MILL_NAME,',
'                :P4_MILL_COUNTRY,',
'                :P4_VC_HEAT_NO,',
'                :P4_SHIP_GST_IN,',
'                SYSTIMESTAMP,',
'                :SESSION_USER_NAME,',
'                :P4_TAX_AMOUNT,',
'                :P4_INVOICE_AMOUNT ,',
'                ''P'',',
'                :P4_PACKING_CHARGES,',
'                :P4_FREIGHT_CHARGES,',
'                :P4_FREIGHT_CHARGES,',
'                :P4_LOADING',
'',
'                 ',
'            );',
'    END;',
'',
'    -- Continue with the cursor processing logic',
'    FOR I IN C LOOP',
'        -- Check the existing quantity and rate',
'          BEGIN',
'                     SELECT ',
'  (',
'    a."Still to be delivered (qty)" - ',
'    NVL((',
'      SELECT SUM(B.NU_QUANTITY)',
'      FROM HD_INVOICE_APP A1, DT_INVOICE_APP B',
'      WHERE A1.NU_LOG_ID = B.NU_PI_LOGID',
'        AND B.VC_PO_NUMBER = I.PO_NUMBER',
'        AND TRIM(B.VC_SAP_ITEM_CODE) = TRIM(I.SAP_ITEM_CODE)',
'        AND B.VC_LINE_NUMBER = I.LINE_NUMBER',
'        and B.NU_QUANTITY=I.QUANTITY',
'        AND A1.VC_MIGO_STATUS = ''P''',
'    ), 0)',
'  ) AS ADJUSTED_DELIVERY_QTY,',
'  ROUND(',
'    CASE ',
'      WHEN a."Purchasing Doc. Type" IN (''ZSCO'', ''ZSFG'') THEN Document_Total_Net_Price',
'      WHEN B.vc_vendor_name IS NOT NULL THEN TO_NUMBER(a."Net Price")',
'      ELSE ',
'        TO_NUMBER(a."Net Price") / ',
'        CASE ',
'          WHEN NVL(TO_NUMBER(a."Price unit"), 0) = 0 THEN 1 ',
'          ELSE TO_NUMBER(a."Price unit") ',
'        END ',
'    END, ',
'    2',
'  )INTO V_QTY,V_RATE',
'  ',
'FROM EBIZAI.VW_PURCHASE_DOC_TOTALS1 A ',
'LEFT JOIN RATE_EXCEPTION B ',
'  ON TRIM(SUBSTR(a."Supplier/Supplying Plant", 7)) = UPPER(B.vc_vendor_name)',
'WHERE a."Purchasing Document" = NVL(I.PO_NUMBER, ''***'')',
'  AND TRIM(a."Material") = TRIM(I.SAP_ITEM_CODE)',
'  AND a."Item" = I.LINE_NUMBER;',
'            -- Validate quantity and rate',
'        IF V_QTY < I.QUANTITY or V_RATE != I.RATE THEN',
'                RAISE_APPLICATION_ERROR(',
'                    -20001, ',
'                    ''Item Code: '' || I.SAP_Item_code || ',
'                    '' - Quantity less than existing or rate mismatch''',
'                );',
'            END IF;',
'        EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'                NULL; -- Proceed with insertion',
'        END;',
'',
'        -- Insert or update the MST_SAP_ITEM_HISTORY table',
'      BEGIN',
'    DECLARE',
'        V_ITEM_COUNT NUMBER;',
'        -- V_DESC_COUNT NUMBER;',
'    BEGIN',
'        -- Check if the item code already exists for the vendor',
'        SELECT COUNT(*)',
'        INTO V_ITEM_COUNT',
'        FROM EBIZAI.MST_SAP_ITEM_HISTORY',
'        WHERE VC_SUPP_ITEM_DESC = I.ITEM_DESC',
'        AND VC_VENDOR_GST_NO=:P4_VENDOR_GST_IN;',
'        --   AND NU_SUPPLIER_CODE = :P4_VC_VENDOR_NAME',
'        --   AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'',
'        IF V_ITEM_COUNT = 0 THEN',
'            -- Insert the new record',
'            INSERT INTO EBIZAI.MST_SAP_ITEM_HISTORY (',
'                VC_COMP_CODE,',
'                VC_SUPP_ITEM_CODE,',
'                VC_SUPP_ITEM_DESC,',
'                NU_QUANTITY,',
'                NU_PRICE,',
'                NU_SUPPLIER_CODE,',
'                VC_VENDOR_NAME,',
'                VC_VENDOR_GST_NO',
'            )',
'            VALUES (',
'                :GLOBAL_COMP_CODE,',
'                I.SAP_Item_code,',
'                NVL(I.ITEM_DESC, ''***''), -- Handle null descriptions',
'                NVL(I.ACTUAL_QTY, 0),    -- Handle null quantities',
'                NVL(I.RATE, 0),          -- Handle null rates',
'                :P4_VC_VENDOR_NAME,',
'                :P4_VC_VENDOR_NAME1,',
'                :P4_VENDOR_GST_IN',
'            );',
'        ELSE',
'            -- Update the existing record',
'            UPDATE EBIZAI.MST_SAP_ITEM_HISTORY',
'            SET  VC_SUPP_ITEM_CODE=I.SAP_Item_code,',
'                NU_QUANTITY = NVL(I.ACTUAL_QTY, 0), -- Update with new quantities',
'                NU_PRICE = NVL(I.RATE, 0)           -- Update with new rates',
'            WHERE VC_SUPP_ITEM_DESC=I.ITEM_DESC',
'            AND VC_VENDOR_GST_NO=:P4_VENDOR_GST_IN;',
'            --   AND NU_SUPPLIER_CODE = :P4_VC_VENDOR_NAME',
'            --   AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'        END IF;',
'        -- END IF;',
'',
'    END;',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        RAISE_APPLICATION_ERROR(-20001, ''No matching records found.'');',
'    WHEN DUP_VAL_ON_INDEX THEN',
'        RAISE_APPLICATION_ERROR(-20002, ''Duplicate value encountered.'');',
'    WHEN OTHERS THEN',
'        RAISE_APPLICATION_ERROR(-20003, ''An unexpected error occurred: '' || SQLERRM);',
'END;',
'',
'        -- Insert or update DT_INVOICE_APP',
'        DECLARE',
'            V_EXISTING_COUNT NUMBER;',
'        BEGIN',
'            SELECT COUNT(*)',
'            INTO V_EXISTING_COUNT',
'            FROM EBIZAI.DT_INVOICE_APP',
'            -- WHERE VC_ITEM_DESC=I.ITEM_DESC',
'           WHERE  NU_PI_LOGID=:P4_NU_LOG_ID',
'            AND VC_SAP_ITEM_CODE = I.SAP_Item_code',
'          AND   VC_LINE_NUMBER=I.LINE_NUMBER',
'            --     AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'               AND VC_INVOICE_NO = :P4_VC_INVOICE_NUMBER',
'               AND VC_HEAT_NO=I.HEAT_NO',
'               AND VC_MILL_NAME=I.MILL_NAME',
'               AND VC_MILL_COUNTRY=I.MILL_COUNTRY;',
'            --    AND NU_QUANTITY=I.QUANTITY;',
'',
'            --    AND DT_INVOICE_DATE=:P4_INVOICE_DATE',
'            --    AND VC_COMP_CODE=:GLOBAL_COMP_CODE;',
'         ',
'            IF V_EXISTING_COUNT = 0 THEN',
'                INSERT INTO EBIZAI.DT_INVOICE_APP (',
'                    VC_ITEM_DESC,',
'                    VC_ITEM_CODE,',
'                    VC_PO_NUMBER,',
'                    DT_PO_DATE,',
'                    VC_SAP_ITEM_CODE,',
'                    VC_LINE_NUMBER,',
'                    VC_HSN_CODE,',
'                    VC_UOM,',
'                    NU_QUANTITY,',
'                    NU_RATE,',
'                    NU_DISCOUNT_PER,',
'                    NU_AMOUNT,',
'                    NU_PI_LOGID,',
'                    NU_VENDOR_CODE,',
'                    VC_INVOICE_NO,',
'                    VC_DUMM_QTY,',
'                    VC_VENDOR_NAME,',
'                    VC_COMP_CODE,',
'                    nu_sap_item_rate,',
'                    nu_sap_item_qty,',
'                    DT_INVOICE_DATE,',
'                    VC_HEAT_NO,',
'                    VC_MILL_NAME,',
'                    VC_MILL_COUNTRY,',
'                    VC_STORAGE_LOCATION',
'',
'                )',
'                VALUES (',
'                    I.ITEM_DESC,',
'                    I.ITEM_CODE,',
'                    I.PO_NUMBER,  ',
'                    I.PO_DATE ,',
'                    I.SAP_Item_code,',
'                    I.LINE_NUMBER,',
'                    I.HSN_CODE,',
'                    I.UOM,',
'                    I.ACTUAL_QTY,',
'                    I.RATE,',
'                    I.DISCOUNT,',
'                    I.AMOUNT,',
'                    V_PI_LOG_ID,',
'                    :P4_VC_VENDOR_NAME,',
'                    :P4_VC_INVOICE_NUMBER,',
'                    I.QUANTITY,',
'                    :P4_VC_VENDOR_NAME1,',
'                    :GLOBAL_COMP_CODE,',
'                     I.SAP_ITEM_RATE  ,   --SAP RATE',
'                     I.SAP_ITEM_QTY,',
'                     :P4_INVOICE_DATE,',
'                     I.HEAT_NO,',
'                     I.MILL_NAME,',
'                     I.MILL_COUNTRY,',
'                     I.STORAGE_LOCATION',
'                    ',
'                );',
'                htp.p(''QUANTITY IS  :P4_QUANTITY'');',
'            ELSE',
'                UPDATE EBIZAI.DT_INVOICE_APP',
'                SET ',
'                    VC_ITEM_DESC = I.ITEM_DESC,',
'                    VC_PO_NUMBER=I.PO_NUMBER,  ',
'                    DT_PO_DATE=  I.PO_DATE ,',
'                    VC_SAP_ITEM_CODE = I.SAP_Item_code,',
'                    VC_LINE_NUMBER=I.LINE_NUMBER,',
'                    VC_HSN_CODE = I.HSN_CODE,',
'                    VC_UOM = I.UOM,',
'                    NU_QUANTITY = I.ACTUAL_QTY,',
'                    NU_RATE = I.RATE,',
'                    NU_DISCOUNT_PER = I.DISCOUNT,',
'                    NU_AMOUNT = I.AMOUNT,',
'                    NU_PI_LOGID = V_PI_LOG_ID,',
'                    VC_DUMM_QTY = I.QUANTITY,',
'                    VC_VENDOR_NAME = :P4_VC_VENDOR_NAME1,',
'                   nu_sap_item_rate=I.SAP_ITEM_RATE ,',
'                    nu_sap_item_qty=I.SAP_ITEM_QTY,',
'                    VC_HEAT_NO=I.HEAT_NO,',
'                    VC_MILL_NAME=I.MILL_NAME,',
'                    VC_MILL_COUNTRY=I.MILL_COUNTRY',
'                  WHERE VC_ITEM_DESC=I.ITEM_DESC',
'                  AND NU_PI_LOGID=:P4_NU_LOG_ID',
'                 AND VC_SAP_ITEM_CODE = I.SAP_Item_code',
'                  AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'                  AND VC_INVOICE_NO = :P4_VC_INVOICE_NUMBER',
'                  AND DT_INVOICE_DATE=:P4_INVOICE_DATE',
'                  AND VC_COMP_CODE=:GLOBAL_COMP_CODE;',
'            END IF;',
'        END;',
'    END LOOP;',
'',
'    -- Update VI_HF_DATA_TBL status',
'    UPDATE EBIZAI.VI_HD_VENDOR_INV ',
'    SET CH_STATUS = ''C'',',
'    VC_HOLD_REASON=NULL,',
'     vc_remark=:P4_VC_REMAKS',
'    WHERE NU_LOG_ID=:P4_NU_LOG_ID',
'    -- VC_INVOICE_NO = :P4_VC_INVOICE_NUMBER',
'    -- and DT_INVOICE_DATE=:P4_INVOICE_DATE',
'    --   AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'    --   AND VC_COMP_CODE=:GLOBAL_COMP_CODE',
'      ;',
'',
'    -- Commit the transaction',
'    COMMIT;',
'',
'    -- Truncate the collection',
'    APEX_COLLECTION.TRUNCATE_COLLECTION(''VENDOR_DT'');',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        ROLLBACK;',
'        RAISE;',
'        -- RAISE_APPLICATION_ERROR(-20001, ''No data found'');',
'END;',
'',
'',
'',
'',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(314291730848633879)
,p_internal_uid=>315219594502072555
);
