wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(68361943303765752)
,p_process_sequence=>50
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Populate data_1'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'-- ------------third code-----------------------------------------',
'-- DECLARE',
'--    v_po_status      VARCHAR2(3);       -- To store status (YES/NO)',
'--    v_sap_item_code  VARCHAR2(50);      -- To store SAP Item Code',
'--    v_line_number    VARCHAR2(50);      -- To store fetched line number',
'--    v_item_count     NUMBER;            -- To store count of items in PO',
'',
'--    CURSOR c_item IS',
'--       SELECT VC_ITEM_DESC, VC_ITEM_CODE, VC_SAP_ITEM_CODE, VC_HSN_CODE, VC_UOM, ',
'--              NU_QUANTITY, VC_DUMM_QTY, NU_RATE, NU_AMOUNT, NU_DISCOUNT_PER, ',
'--              VC_PO_NUMBER, DT_PO_DATE',
'--       FROM EBIZAI.VI_DT_VENDOR_INV',
'--       WHERE VC_INVOICE_NO = :P4_VC_INVOICE_NUMBER',
'--         AND DT_INVOICE_DATE = TO_DATE(:P4_INVOICE_DATE, ''MM-DD-YY'')',
'--         AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'--         AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'',
'-- BEGIN',
'--    -- Check if the APEX collection exists, and create or truncate it accordingly',
'--    IF NOT apex_collection.collection_exists(''VENDOR_DT'') THEN',
'--       apex_collection.create_collection(''VENDOR_DT'');',
'--    ELSE',
'--       apex_collection.truncate_collection(''VENDOR_DT'');',
'--    END IF;',
'',
'--    -- Generate a global document number (current timestamp)',
'--    SELECT TO_CHAR(SYSDATE, ''YYYYMMDDHH24MISS'') INTO :GLOBAL_DOC_NO FROM dual;',
'',
'--    -- Loop through each row in the cursor and process individually',
'--    FOR c IN c_item LOOP',
'--       BEGIN',
'--          -- Check PO Status (YES/NO)',
'--          BEGIN',
'--             SELECT CASE ',
'--                       WHEN COUNT(*) > 0 THEN ''YES'' ',
'--                       ELSE ''NO'' ',
'--                    END ',
'--             INTO v_po_status',
'--             FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'--             -- FROM EBIZAI.VENDORPENDINGPOS',
'--             WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'--             --  and vc_gst_no=:P4_VENDOR_GST_IN',
'--               AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'--               AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'--          EXCEPTION',
'--             WHEN NO_DATA_FOUND THEN',
'--                v_po_status := ''NO'';',
'--          END;',
'',
'--          -- Count the number of line items in the PO',
'--          BEGIN',
'--             SELECT COUNT(*) ',
'--             INTO v_item_count',
'--             FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'--             WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'--               AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'--               AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'--          EXCEPTION',
'--             WHEN NO_DATA_FOUND THEN',
'--                v_item_count := 0;',
'--          END;',
'',
'--          -- Fetch SAP Item Code from vw_sap_pending_po_vendor_gst if exactly one item exists',
'--          BEGIN',
'--             IF v_item_count = 1 THEN',
'--                SELECT VC_ITEM_CODE  ',
'--                INTO v_sap_item_code',
'--                FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'--                WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'--                  AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'--                  AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'--             ELSE',
'--                v_sap_item_code := NULL; -- Set NULL if multiple items exist',
'--             END IF;',
'--          EXCEPTION',
'--             WHEN NO_DATA_FOUND THEN',
'--                v_sap_item_code := NULL;',
'--          END;',
'',
'--          -- If SAP Item Code is still NULL, fetch from MST_SAP_ITEM_HISTORY',
'--          IF v_sap_item_code IS NULL THEN',
'--             BEGIN',
'--                SELECT VC_SUPP_ITEM_CODE ',
'--                INTO v_sap_item_code',
'--                FROM MST_SAP_ITEM_HISTORY',
'--                WHERE VC_SUPP_ITEM_DESC = c.VC_ITEM_DESC',
'--                  AND NU_SUPPLIER_CODE = :P4_VC_VENDOR_NAME',
'--                  AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'--             EXCEPTION',
'--                WHEN NO_DATA_FOUND THEN',
'--                   v_sap_item_code := NULL;',
'--             END;',
'--          END IF;',
'',
'--          -- Fetch Line Number',
'--          BEGIN',
'--             SELECT MAX(VC_LINE_NUMBER) -- Fetch the highest available line number',
'--             INTO v_line_number',
'--             FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'--             WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'--               AND VC_ITEM_CODE = NVL(v_sap_item_code, c.VC_ITEM_CODE) -- Use SAP code if available',
'--               AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'--               AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'--          EXCEPTION',
'--             WHEN NO_DATA_FOUND THEN',
'--                v_line_number := NULL;',
'--          END;',
'',
'--          -- Add the row to the APEX collection',
'--          apex_collection.add_member (',
'--             p_collection_name => ''VENDOR_DT'',',
'--             p_C001            => c.VC_ITEM_DESC,       -- ITEM_DESC (Description)',
'--             p_C002            => c.VC_ITEM_CODE,       -- ITEM_CODE (Item Code)',
'--             p_C003            => c.VC_HSN_CODE,        -- HSN_CODE (HSN Code)',
'--             p_C004            => c.VC_UOM,             -- UOM (Unit of Measure)',
'--             p_C005            => v_sap_item_code,      -- SAP Item Code (from vw_sap_pending_po_vendor_gst or MST_SAP_ITEM_HISTORY)',
'--             p_N003            => c.NU_QUANTITY,        -- QUANTITY',
'--             p_N004            => round(c.NU_RATE,2),   -- RATE',
'--             p_N005            => c.NU_AMOUNT,          -- AMOUNT',
'--             p_C006            => ''NONE'',               -- Static value for C006',
'--             p_C007            => c.VC_ITEM_CODE,       -- ITEM_CODE (Item Code for reference)    ',
'--             p_C009            => c.NU_DISCOUNT_PER,    -- Discount Percentage          ',
'--             p_C050            => :GLOBAL_DOC_NO,       -- Global Document Number',
'--             p_C008            => c.NU_QUANTITY,',
'--             p_C010            => c.VC_PO_NUMBER,',
'--             p_D001            => c.DT_PO_DATE,         -- PO Date',
'--             p_C011            => v_line_number,        -- Line Number',
'--             p_C012            => v_po_status           -- PO Status (YES/NO)',
'--          );',
'--       END;',
'--    END LOOP;',
'-- EXCEPTION ',
'--    WHEN NO_DATA_FOUND THEN',
'--       RAISE_APPLICATION_ERROR(-20001, ''No data found'');',
'-- END;',
'',
'------------------------Developed by Kunal Agarwal ---------------------------------------------',
'-----------------Changed on the 05/04/2024------------------',
'--------------------updated code -----------------------------------',
'------------third code-----------------------------------------',
'',
'DECLARE',
'   v_po_status      VARCHAR2(3);       -- To store status (YES/NO)',
'   v_sap_item_code  VARCHAR2(50);      -- To store SAP Item Code',
'   v_line_number    VARCHAR2(50);      -- To store fetched line number',
'   v_item_count     NUMBER;            -- To store count of items in PO',
'',
'   CURSOR c_item IS',
'      SELECT VC_ITEM_DESC, VC_ITEM_CODE, VC_SAP_ITEM_CODE, VC_HSN_CODE, VC_UOM, ',
'             NU_QUANTITY, VC_DUMM_QTY, NU_RATE, NU_AMOUNT, NU_DISCOUNT_PER, ',
'             VC_PO_NUMBER, DT_PO_DATE',
'      FROM EBIZAI.VI_DT_VENDOR_INV',
'      WHERE NU_PI_LOGID =:P4_NU_LOG_ID;',
'    --   VC_INVOICE_NO = :P4_VC_INVOICE_NUMBER',
'    --     AND DT_INVOICE_DATE = TO_DATE(:P4_INVOICE_DATE, ''MM-DD-YY'')',
'    --     AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'    --     AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'',
'BEGIN',
'   -- Check if the APEX collection exists, and create or truncate it accordingly',
'   IF NOT apex_collection.collection_exists(''VENDOR_DT'') THEN',
'      apex_collection.create_collection(''VENDOR_DT'');',
'   ELSE',
'      apex_collection.truncate_collection(''VENDOR_DT'');',
'   END IF;',
'',
'   -- Generate a global document number (current timestamp)',
'   SELECT TO_CHAR(SYSDATE, ''YYYYMMDDHH24MISS'') INTO :GLOBAL_DOC_NO FROM dual;',
'',
'   -- Loop through each row in the cursor and process individually',
'   FOR c IN c_item LOOP',
'      BEGIN',
'         -- Check PO Status (YES/NO)',
'         BEGIN',
'            SELECT CASE ',
'                      WHEN COUNT(*) > 0 THEN ''YES'' ',
'                      ELSE ''NO'' ',
'                   END ',
'            INTO v_po_status',
'            FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'            -- FROM EBIZAI.VENDORPENDINGPOS',
'            WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'             and vc_gst_no=:P4_VENDOR_GST_IN',
'            --   AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'              AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'         EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'               v_po_status := ''NO'';',
'         END;',
'',
'         -- Count the number of line items in the PO',
'         BEGIN',
'            SELECT COUNT(*) ',
'            INTO v_item_count',
'            FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'            WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'            --   AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'                and  VC_GST_NO=:P4_VENDOR_GST_IN',
'              AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'         EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'               v_item_count := 0;',
'         END;',
'',
'         -- Fetch SAP Item Code from vw_sap_pending_po_vendor_gst if exactly one item exists',
'         BEGIN',
'            IF v_item_count = 1 THEN',
'               SELECT VC_ITEM_CODE  ',
'               INTO v_sap_item_code',
'               FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'               WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'                --  AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'                and  VC_GST_NO=:P4_VENDOR_GST_IN',
'                 AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'            ELSE',
'               v_sap_item_code := NULL; -- Set NULL if multiple items exist',
'            END IF;',
'         EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'               v_sap_item_code := NULL;',
'         END;',
'',
'         -- If SAP Item Code is still NULL, fetch from MST_SAP_ITEM_HISTORY',
'         IF v_sap_item_code IS NULL THEN',
'            BEGIN',
'               SELECT VC_SUPP_ITEM_CODE ',
'               INTO v_sap_item_code',
'               FROM MST_SAP_ITEM_HISTORY',
'               WHERE VC_SUPP_ITEM_DESC = c.VC_ITEM_DESC',
'                 AND VC_VENDOR_GST_NO=:P4_VENDOR_GST_IN;',
'                --   NU_SUPPLIER_CODE = :P4_VC_VENDOR_NAME',
'                -- and  VC_GST_NO=:P4_VENDOR_GST_IN',
'                --  AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'            EXCEPTION',
'               WHEN NO_DATA_FOUND THEN',
'                  v_sap_item_code := NULL;',
'            END;',
'         END IF;',
'',
'         -- Fetch Line Number',
'         BEGIN',
'            SELECT MAX(VC_LINE_NUMBER) -- Fetch the highest available line number',
'            INTO v_line_number',
'            FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'            WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'              AND VC_ITEM_CODE = NVL(v_sap_item_code, c.VC_ITEM_CODE) -- Use SAP code if available',
'            --   AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'            and  VC_GST_NO=:P4_VENDOR_GST_IN',
'              AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'         EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'               v_line_number := NULL;',
'         END;',
'',
'         -- Add the row to the APEX collection',
'         apex_collection.add_member (',
'            p_collection_name => ''VENDOR_DT'',',
'            p_C001            => c.VC_ITEM_DESC,       -- ITEM_DESC (Description)',
'            p_C002            => c.VC_ITEM_CODE,       -- ITEM_CODE (Item Code)',
'            p_C003            => c.VC_HSN_CODE,        -- HSN_CODE (HSN Code)',
'            p_C004            => c.VC_UOM,             -- UOM (Unit of Measure)',
'            p_C005            => v_sap_item_code,      -- SAP Item Code (from vw_sap_pending_po_vendor_gst or MST_SAP_ITEM_HISTORY)',
'            p_N003            => c.NU_QUANTITY,        -- QUANTITY',
'            p_N004            => round(c.NU_RATE,4),   -- RATE',
'            p_N005            => c.NU_AMOUNT,          -- AMOUNT',
'            p_C006            => ''NONE'',               -- Static value for C006',
'            p_C007            => c.VC_ITEM_CODE,       -- ITEM_CODE (Item Code for reference)    ',
'            p_C009            => c.NU_DISCOUNT_PER,    -- Discount Percentage          ',
'            p_C050            => :GLOBAL_DOC_NO,       -- Global Document Number',
'            p_C008            => c.NU_QUANTITY,',
'            p_C010            => c.VC_PO_NUMBER,',
'            p_D001            => c.DT_PO_DATE,         -- PO Date',
'            p_C011            => v_line_number,        -- Line Number',
'            p_C012            =>v_po_status        -- PO Status (YES/NO)',
'         );',
'      END;',
'   END LOOP;',
'EXCEPTION ',
'   WHEN NO_DATA_FOUND THEN',
'      RAISE_APPLICATION_ERROR(-20001, ''No data found'');',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(315217638116072535)
,p_process_when=>'P4_ACTION'
,p_process_when_type=>'VAL_OF_ITEM_IN_COND_EQ_COND2'
,p_process_when2=>'A'
,p_internal_uid=>68361943303765752
);
end;
