wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(8438980723684872)
,p_process_sequence=>10
,p_process_point=>'BEFORE_BOX_BODY'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Populate date'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'if :P4_ACTION=''A'' THEN',
'DECLARE',
'   v_po_status      VARCHAR2(3);       -- To store status (YES/NO)',
'   v_sap_item_code  VARCHAR2(50);      -- To store SAP Item Code',
'   v_line_number    VARCHAR2(50);      -- To store fetched line number',
'   v_item_count     NUMBER; ',
'   v_item_count_invoice number;           -- To store count of items in PO',
'   V_SAP_RATE        NUMBER;',
'   V_SAP_QTY         NUMBER;',
'   v_mill_name       varchar2(50);',
'   v_mill_country    varchar2(50);',
'   v_mill_heat_no    varchar2(50);',
'   V_STORAGE_LOCATION VARCHAR2(20);',
'   vc_po_number       varchar2(50);',
'   v_po_count         number;',
'',
'   CURSOR c_item IS',
'      SELECT A.VC_ITEM_DESC, A.VC_ITEM_CODE, A.VC_SAP_ITEM_CODE, A.VC_HSN_CODE, A.VC_UOM, ',
'             A.NU_QUANTITY, A.VC_DUMM_QTY, ',
'             CASE WHEN B.VC_VENDOR_GSTIN =''06ABDFM6263D1ZG'' then A.NU_RATE',
'             ELSE A.nu_rate - (A.nu_rate * (A.nu_discount_per / 100)) ',
'             END AS NU_RATE',
'             , A.NU_AMOUNT, A.NU_DISCOUNT_PER, ',
'             A.VC_PO_NUMBER, A.DT_PO_DATE',
'      FROM EBIZAI.VI_DT_VENDOR_INV A,EBIZAI.VI_HD_VENDOR_INV B ',
'      WHERE A.NU_PI_LOGID=B.NU_LOG_ID',
'      AND A.NU_PI_LOGID = :P4_NU_LOG_ID;',
'',
'BEGIN',
'   -- Check if the APEX collection exists, and create or truncate it accordingly',
'   IF NOT apex_collection.collection_exists(''VENDOR_DT'') THEN',
'      apex_collection.create_collection(''VENDOR_DT'');',
'   ELSE',
'      apex_collection.truncate_collection(''VENDOR_DT'');',
'   END IF;',
'',
'   -- Generate a global document number (current timestamp)',
'   SELECT TO_CHAR(SYSDATE, ''YYYYMMDDHH24MISS'') INTO :GLOBAL_DOC_NO FROM dual;',
'',
'   -- Loop through each row in the cursor and process individually',
'   FOR c IN c_item LOOP',
'      BEGIN',
'',
'       begin ',
' if c.VC_PO_NUMBER is null then',
'       SELECT count(distinct',
'            --    i.VC_ITEM_DESC,',
'       --p.VC_PO_NUMBER,',
'       CASE ',
'         WHEN INSTR(i.VC_ITEM_DESC, p.VC_PO_NUMBER) > 0 THEN p.VC_PO_NUMBER',
'         ELSE NULL',
'       END) into v_po_count',
'FROM vi_dt_vendor_inv i',
'JOIN vw_sap_pending_po_vendor_gst p',
'  ON INSTR(i.VC_ITEM_DESC, p.VC_PO_NUMBER) > 0',
'  where NU_PI_LOGID=:P4_NU_LOG_ID',
'  and i.VC_ITEM_DESC = c.VC_ITEM_DESC;',
'',
'  if v_po_count=1 then',
'       ',
'               SELECT distinct',
'            --    i.VC_ITEM_DESC,',
'       --p.VC_PO_NUMBER,',
'       CASE ',
'         WHEN INSTR(i.VC_ITEM_DESC, p.VC_PO_NUMBER) > 0 THEN p.VC_PO_NUMBER',
'         ELSE NULL',
'       END into vc_po_number',
'FROM vi_dt_vendor_inv i',
'JOIN vw_sap_pending_po_vendor_gst p',
'  ON INSTR(i.VC_ITEM_DESC, p.VC_PO_NUMBER) > 0',
'  where NU_PI_LOGID=:P4_NU_LOG_ID',
'  and i.VC_ITEM_DESC = c.VC_ITEM_DESC;',
'  c.VC_PO_NUMBER:=vc_po_number;',
'  end if;',
'  end if;',
'',
'    -- c.VC_PO_NUMBER:=vc_po_number;',
'   EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'               vc_po_number := NULL;',
'        --  END;',
'   end;',
'         -- Check PO Status (YES/NO)',
'         BEGIN',
'            SELECT CASE ',
'                      WHEN COUNT(*) > 0 THEN ''YES'' ',
'                      ELSE ''NO'' ',
'                   END ',
'            INTO v_po_status',
'            FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'            WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'              AND VC_GST_NO = :P4_VENDOR_GST_IN',
'              AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'         EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'               v_po_status := ''NO'';',
'         END;',
'',
'         -- Count the number of line items in the PO',
'         BEGIN',
'            SELECT COUNT(*) ',
'            INTO v_item_count',
'            FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'            WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'              AND VC_GST_NO = :P4_VENDOR_GST_IN',
'              AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'         EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'               v_item_count := 0;',
'         END;',
'',
'           -- Count the number of line items in the invoice',
'         BEGIN',
'            SELECT COUNT(*) ',
'            INTO v_item_count_invoice',
'            FROM EBIZAI.vi_dt_vendor_inv',
'             WHERE NU_PI_LOGID = :P4_NU_LOG_ID;',
'         EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'               v_item_count_invoice := 0;',
'         END;',
'',
'         -- Fetch SAP Item Code from vw_sap_pending_po_vendor_gst if exactly one item exists',
'         BEGIN',
'            IF v_item_count = 1 and v_item_count_invoice =1 THEN',
'               SELECT DISTINCT(VC_ITEM_CODE)  ',
'               INTO v_sap_item_code',
'               FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'               WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'                 AND VC_GST_NO = :P4_VENDOR_GST_IN',
'                 AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'            ELSE',
'               v_sap_item_code := NULL;',
'            END IF;',
'         EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'               v_sap_item_code := NULL;',
'         END;',
'',
'         -- If SAP Item Code is still NULL, fetch from MST_SAP_ITEM_HISTORY',
'        --  IF v_sap_item_code IS NULL THEN',
'        --     BEGIN',
'        --        SELECT VC_SUPP_ITEM_CODE ',
'        --        INTO v_sap_item_code',
'        --        FROM MST_SAP_ITEM_HISTORY',
'        --     --    WHERE VC_SUPP_ITEM_DESC LIKE  TRIM(''%'' || c.VC_ITEM_DESC || ''%'')',
'        --     WHERE TRIM(VC_SUPP_ITEM_DESC) =  c.VC_ITEM_DESC',
'        --          AND VC_VENDOR_GST_NO = :P4_VENDOR_GST_IN;',
'        --     EXCEPTION',
'        --        WHEN NO_DATA_FOUND THEN',
'        --           v_sap_item_code := NULL;',
'        --     END;',
'        --  END IF;',
'',
'        IF v_sap_item_code IS NULL THEN',
'   DECLARE',
'      v_count NUMBER;',
'   BEGIN',
'      SELECT COUNT(*)',
'      INTO v_count',
'      FROM MST_SAP_ITEM_HISTORY',
'      WHERE TRIM(VC_SUPP_ITEM_DESC) = c.VC_ITEM_DESC',
'        AND VC_VENDOR_GST_NO = :P4_VENDOR_GST_IN;',
'',
'      IF v_count = 1 THEN',
'         SELECT VC_SUPP_ITEM_CODE ',
'         INTO v_sap_item_code',
'         FROM MST_SAP_ITEM_HISTORY',
'         WHERE TRIM(VC_SUPP_ITEM_DESC) = c.VC_ITEM_DESC',
'           AND VC_VENDOR_GST_NO = :P4_VENDOR_GST_IN;',
'      ELSE',
'         v_sap_item_code := NULL;',
'      END IF;',
'',
'   EXCEPTION',
'      WHEN NO_DATA_FOUND THEN',
'         v_sap_item_code := NULL;',
'   END;',
'END IF;',
'',
'         -- If SAP Item Code is still NULL, try matching from OPEN_PURCHASES_ORDER',
'         IF v_sap_item_code IS NULL THEN',
'            DECLARE',
'               v_match_count NUMBER;',
'            BEGIN',
'               -- Count potential matches',
'               SELECT COUNT(*)',
'               INTO v_match_count',
'               FROM OPEN_PURCHASES_ORDER',
'               WHERE "Purchasing Document" = c.VC_PO_NUMBER',
'                 AND (',
'                    upper(c.VC_ITEM_DESC) LIKE ''%'' || upper("Material") || ''%''',
'                         OR upper(c.VC_ITEM_DESC) LIKE ''%'' || upper("Short Text") || ''%''',
'                 );',
'',
'               -- Only fetch item code if exactly one match found',
'               IF v_match_count = 1 THEN',
'                  SELECT "Material"',
'                  INTO v_sap_item_code',
'                  FROM OPEN_PURCHASES_ORDER',
'                  WHERE "Purchasing Document" = c.VC_PO_NUMBER',
'                    AND (',
'                        upper(c.VC_ITEM_DESC) LIKE ''%'' || upper("Material") || ''%''',
'                         OR upper(c.VC_ITEM_DESC) LIKE ''%'' || upper("Short Text") || ''%''',
'                    );',
'                    ',
'               ELSE',
'                  v_sap_item_code := NULL;',
'               END IF;',
'            EXCEPTION',
'               WHEN NO_DATA_FOUND THEN',
'                  v_sap_item_code := NULL;',
'            END;',
'         END IF;',
'',
'         -- Fetch Line Number',
'         BEGIN',
'            SELECT MIN(VC_LINE_NUMBER)',
'            INTO v_line_number',
'            FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'            WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'              AND VC_ITEM_CODE = NVL(v_sap_item_code, c.VC_ITEM_CODE)',
'              AND VC_GST_NO = :P4_VENDOR_GST_IN',
'              AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'         EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'               v_line_number := NULL;',
'         END;',
'-------------------FOR SAP RATE AND QTY----------------',
'          BEGIN',
'',
'--         SELECT ',
'--   (',
'--     "Still to be delivered (qty)" - ',
'--     NVL((',
'--       SELECT B.NU_QUANTITY',
'-- FROM HD_INVOICE_APP A, DT_INVOICE_APP B',
'-- WHERE A.NU_LOG_ID=B.NU_PI_LOGID',
'-- AND B.VC_PO_NUMBER=c.vc_po_number',
'-- AND TRIM(B.VC_SAP_ITEM_CODE) = TRIM(v_sap_item_code)',
'-- AND B.VC_LINE_NUMBER=v_line_number',
'-- AND A.VC_MIGO_STATUS=''P''',
'--     ), 0)',
'--   ) AS ADJUSTED_DELIVERY_QTY,',
'--   ROUND(',
'--     CASE ',
'--       WHEN "Purchasing Doc. Type" IN (''ZSCO'', ''ZSFG'') THEN Document_Total_Net_Price',
'--       ELSE ',
'--         TO_NUMBER("Net Price") / ',
'--         CASE ',
'--           WHEN NVL(TO_NUMBER("Price unit"), 0) = 0 THEN 1 ',
'--           ELSE TO_NUMBER("Price unit") ',
'--         END ',
'--     END, ',
'--     2',
'--   )',
'-- INTO V_SAP_QTY,V_SAP_RATE',
'-- FROM EBIZAI.VW_PURCHASE_DOC_TOTALS',
'-- WHERE "Purchasing Document" = NVL(c.VC_PO_NUMBER, ''***'')',
'--   AND TRIM("Material") = TRIM(v_sap_item_code)',
'--   AND "Item" = v_line_number;',
'SELECT ',
'  (',
'    a."Still to be delivered (qty)" - ',
'    NVL((',
'      SELECT SUM(B.NU_QUANTITY)',
'      FROM HD_INVOICE_APP A1, DT_INVOICE_APP B',
'      WHERE A1.NU_LOG_ID = B.NU_PI_LOGID',
'        AND B.VC_PO_NUMBER = c.vc_po_number',
'        AND TRIM(B.VC_SAP_ITEM_CODE) = TRIM(v_sap_item_code)',
'        AND B.VC_LINE_NUMBER = v_line_number',
'        -- and B.NU_QUANTITY=C.NU_QUANTITY',
'        AND A1.VC_MIGO_STATUS = ''P''',
'        -- AND ROWNUM = 1',
'        -- AND B.NU_LOG_ID=:P4_NU_LOG_ID',
'    ), 0)',
'  ) AS ADJUSTED_DELIVERY_QTY,',
'  ROUND(',
'    CASE ',
'      WHEN a."Purchasing Doc. Type" IN (''ZSCO'', ''ZSFG'') THEN Document_Total_Net_Price',
'      WHEN B.vc_vendor_name IS NOT NULL THEN TO_NUMBER(a."Net Price")',
'      ELSE ',
'        TO_NUMBER(a."Net Price") / ',
'        CASE ',
'          WHEN NVL(TO_NUMBER(a."Price unit"), 0) = 0 THEN 1 ',
'          ELSE TO_NUMBER(a."Price unit") ',
'        END ',
'    END, ',
'    2',
'  ),A."Storage location"',
'  INTO V_SAP_QTY,V_SAP_RATE,V_STORAGE_LOCATION',
'  ',
'FROM EBIZAI.VW_PURCHASE_DOC_TOTALS1 A ',
'LEFT JOIN RATE_EXCEPTION B ',
'  ON TRIM(SUBSTR(a."Supplier/Supplying Plant", 7)) = UPPER(B.vc_vendor_name)',
'WHERE a."Purchasing Document" = NVL(c.vc_po_number, ''***'')',
'  AND TRIM(a."Material") = TRIM(v_sap_item_code)',
'  AND a."Item" = v_line_number;',
'         EXCEPTION',
'            WHEN NO_DATA_FOUND THEN',
'               V_SAP_QTY := NULL;',
'               V_SAP_RATE := NULL;',
'         END;',
'',
'         -- Add the row to the APEX collection',
'         apex_collection.add_member (',
'            p_collection_name => ''VENDOR_DT'',',
'            p_C001            => c.VC_ITEM_DESC,',
'            p_C002            => c.VC_ITEM_CODE,',
'            p_C003            => c.VC_HSN_CODE,',
'            p_C004            => c.VC_UOM,',
'            p_C005            => v_sap_item_code,',
'            p_N003            => c.NU_QUANTITY,',
'            p_N004            => ROUND(c.NU_RATE, 2),',
'            p_N005            => c.NU_AMOUNT,',
'            p_C006            => ''NONE'',',
'            p_C007            => c.VC_ITEM_CODE,',
'            p_C009            => c.NU_DISCOUNT_PER,',
'            p_C050            => :GLOBAL_DOC_NO,',
'            p_C008            => c.NU_QUANTITY,',
'            p_C010            => c.VC_PO_NUMBER,',
'            p_D001            => c.DT_PO_DATE,',
'            p_C011            => v_line_number,',
'            p_C012            => v_po_status,',
'            P_N001            =>V_SAP_RATE,',
'            P_N002            =>V_SAP_QTY,',
'            P_C013            =>v_mill_heat_no,',
'            P_C014            =>v_mill_name,',
'            P_C015            =>v_mill_country,',
'            P_C016            =>V_STORAGE_LOCATION',
'',
'         );',
'      END;',
'   END LOOP;',
'EXCEPTION ',
'   WHEN NO_DATA_FOUND THEN',
'      RAISE_APPLICATION_ERROR(-20001, ''No data found'');',
'END;',
'-----------------------NEW CODE---------------',
'-- ELSE IF :P4_ACTION=''V1''',
'',
'ELSE',
'DECLARE',
'   v_po_status      VARCHAR2(3);       -- To store status (YES/NO)',
'   v_sap_item_code  VARCHAR2(50);      -- To store SAP Item Code',
'   v_line_number    VARCHAR2(50);      -- To store fetched line number',
'   v_item_count     NUMBER;            -- To store count of items in PO',
'   v_mill_name       varchar2(50);',
'   v_mill_country    varchar2(50);',
'   v_mill_heat_no    varchar2(50);',
'',
'   CURSOR c_item IS',
'  SELECT VC_ITEM_DESC, VC_ITEM_CODE,VC_LINE_NUMBER, VC_SAP_ITEM_CODE, VC_HSN_CODE, VC_UOM, ',
'             NU_QUANTITY, VC_DUMM_QTY, NU_RATE, NU_AMOUNT, NU_DISCOUNT_PER, ',
'             VC_PO_NUMBER, DT_PO_DATE,NU_SAP_ITEM_RATE,NU_SAP_ITEM_QTY,VC_HEAT_NO,VC_MILL_NAME,VC_MILL_COUNTRY,VC_STORAGE_LOCATION',
'      FROM EBIZAI.DT_INVOICE_APP',
'      WHERE NU_PI_LOGID=:P4_NU_LOG_ID;',
'',
'BEGIN',
'   -- Check if the APEX collection exists, and create or truncate it accordingly',
'   IF NOT apex_collection.collection_exists(''VENDOR_DT'') THEN',
'      apex_collection.create_collection(''VENDOR_DT'');',
'   ELSE',
'      apex_collection.truncate_collection(''VENDOR_DT'');',
'   END IF;',
'',
'   -- Generate a global document number (current timestamp)',
'   SELECT TO_CHAR(SYSDATE, ''YYYYMMDDHH24MISS'') INTO :GLOBAL_DOC_NO FROM dual;',
'',
'--    Loop through each row in the cursor and process individually',
'   FOR c IN c_item LOOP',
'      BEGIN',
'         -- Check PO Status (YES/NO)',
'        --  BEGIN',
'        --     SELECT ',
'        --     CASE ',
'        --               WHEN COUNT(*) > 0 THEN ''YES'' ',
'        --               ELSE ''NO'' ',
'        --            END ',
'        --     INTO v_po_status',
'        --      FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'        --     -- FROM EBIZAI.VENDORPENDINGPOS',
'        --     WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'        --      and vc_gst_no=:P4_VENDOR_GST_IN',
'        --     --   AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'        --       AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'        --  EXCEPTION',
'        --     WHEN NO_DATA_FOUND THEN',
'        --        v_po_status := ''NO'';',
'        --  END;',
'',
'         -- Count the number of line items in the PO',
'        --  BEGIN',
'        --     SELECT COUNT(*) ',
'        --     INTO v_item_count',
'        --     FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'        --     -- FROM EBIZAI.VENDORPENDINGPOS',
'        --     WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'        --      and vc_gst_no=:P4_VENDOR_GST_IN',
'        --     --   AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'        --       AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'        --  EXCEPTION',
'        --     WHEN NO_DATA_FOUND THEN',
'        --        v_item_count := 0;',
'        --  END;',
'',
'        --  -- Fetch SAP Item Code from SAP_PENDING_PO_TBL if exactly one item exists',
'        --  BEGIN',
'        --     IF v_item_count = 1 THEN',
'        --        SELECT VC_ITEM_CODE  ',
'        --        INTO v_sap_item_code',
'        --       FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'        --     -- FROM EBIZAI.VENDORPENDINGPOS',
'        --     WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'        --      and vc_gst_no=:P4_VENDOR_GST_IN',
'        --     --   AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'        --       AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'        --     ELSE',
'        --        v_sap_item_code := NULL; -- Set NULL if multiple items exist',
'        --     END IF;',
'        --  EXCEPTION',
'        --     WHEN NO_DATA_FOUND THEN',
'        --        v_sap_item_code := NULL;',
'        --  END;',
'',
'        --  -- If SAP Item Code is still NULL, fetch from MST_SAP_ITEM_HISTORY',
'        --  IF v_sap_item_code IS NULL THEN',
'        --     BEGIN',
'        --        SELECT VC_SUPP_ITEM_CODE ',
'        --        INTO v_sap_item_code',
'        --        FROM MST_SAP_ITEM_HISTORY',
'        --        WHERE VC_SUPP_ITEM_DESC = c.VC_ITEM_DESC',
'        --          AND VC_VENDOR_GST_NO=:P4_VENDOR_GST_IN;',
'        --     EXCEPTION',
'        --        WHEN NO_DATA_FOUND THEN',
'        --           v_sap_item_code := NULL;',
'        --     END;',
'        --  END IF;',
'',
'        --  -- Fetch Line Number',
'        --  BEGIN',
'        --     SELECT MAX(VC_LINE_NUMBER) -- Fetch the highest available line number',
'        --     INTO v_line_number',
'        --         FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'        --     WHERE VC_PO_NUMBER = c.VC_PO_NUMBER',
'        --       AND VC_ITEM_CODE = NVL(v_sap_item_code, c.VC_ITEM_CODE) -- Use SAP code if available',
'        --     --   AND NU_VENDOR_CODE = :P4_VC_VENDOR_NAME',
'        --     and  VC_GST_NO=:P4_VENDOR_GST_IN',
'        --       AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'        --  EXCEPTION',
'        --     WHEN NO_DATA_FOUND THEN',
'        --        v_line_number := NULL;',
'        --  END;',
'',
'--          -- Add the row to the APEX collection',
'         apex_collection.add_member (',
'            p_collection_name => ''VENDOR_DT'',',
'            p_C001            => c.VC_ITEM_DESC,       -- ITEM_DESC (Description)',
'            p_C002            => c.VC_ITEM_CODE,       -- ITEM_CODE (Item Code)',
'            p_C003            => c.VC_HSN_CODE,        -- HSN_CODE (HSN Code)',
'            p_C004            => c.VC_UOM,             -- UOM (Unit of Measure)',
'            p_C005            => c.VC_SAP_ITEM_CODE,      -- SAP Item Code (from SAP_PENDING_PO_TBL or MST_SAP_ITEM_HISTORY)',
'            p_N003            => c.NU_QUANTITY,        -- QUANTITY',
'            p_N004            => round(c.NU_RATE,2),   -- RATE',
'            p_N005            => c.NU_AMOUNT,          -- AMOUNT',
'            p_C006            => ''NONE'',               -- Static value for C006',
'            p_C007            => c.VC_ITEM_CODE,       -- ITEM_CODE (Item Code for reference)    ',
'            p_C009            => c.NU_DISCOUNT_PER,    -- Discount Percentage          ',
'            p_C050            => :GLOBAL_DOC_NO,       -- Global Document Number',
'            p_C008            => c.NU_QUANTITY,',
'            p_C010            => c.VC_PO_NUMBER,',
'            p_D001            => c.DT_PO_DATE,         -- PO Date',
'            p_C011            => c.VC_LINE_NUMBER,        -- Line Number',
'            p_C012            => ''YES''      ,    -- PO Status (YES/NO)',
'            P_N001            =>c.NU_SAP_ITEM_RATE,',
'            P_N002            =>c.NU_SAP_ITEM_QTY,',
'            P_C013            =>c.VC_HEAT_NO,',
'            P_C014            =>c.VC_MILL_NAME,',
'            P_C015            =>c.VC_MILL_COUNTRY,',
'            P_C016            =>c.VC_STORAGE_LOCATION',
'         );',
'      END;',
'   END LOOP;',
'EXCEPTION ',
'   WHEN NO_DATA_FOUND THEN',
'      RAISE_APPLICATION_ERROR(-20001, ''No data found'');',
'END;',
'END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
