begin
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(68362221017765754)
,p_process_sequence=>40
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'VALIDATE_AND_UPDATE_VENDOR_1'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'-- ------------------------Developed by Kunal Agarwal ---------------------------------------------',
'-- ---------last updated on 04/04/2025----------------------------------------------------------',
'',
'',
'-----------fourth code-----------',
'DECLARE',
'    V_QTY        NUMBER;',
'    V_RATE       NUMBER;',
'    V_COUNT      NUMBER;',
'    v_po_status  VARCHAR2(5);',
'    v_error_msg  VARCHAR2(1000) := NULL;',
'BEGIN',
'    -- Check if item exists in PO',
'    SELECT COUNT(*)',
'    INTO V_COUNT',
'    FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'    WHERE VC_PO_NUMBER = :P4_PO_NUMBER1',
'      AND vc_gst_no = :P4_VENDOR_GST_IN',
'      AND VC_ITEM_CODE = :P4_SAP_ITEM_CODE1',
'      AND VC_LINE_NUMBER = :P4_LINE_NUMBER',
'      AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'',
'    IF V_COUNT = 0 THEN',
'        v_error_msg := ''ITEM_NOT_IN_PO'';',
'    END IF;',
'',
'    -- Fetch quantity and rate',
'    BEGIN',
'        -- SELECT ',
'        --     ("Still to be delivered (qty)" - ',
'        --      NVL((SELECT B.NU_QUANTITY',
'        --           FROM HD_INVOICE_APP A, DT_INVOICE_APP B',
'        --           WHERE A.NU_LOG_ID = B.NU_PI_LOGID',
'        --             AND B.VC_PO_NUMBER = :P4_PO_NUMBER1',
'        --             AND TRIM(B.VC_SAP_ITEM_CODE) = TRIM(:P4_SAP_ITEM_CODE1)',
'        --             AND B.VC_LINE_NUMBER = :P4_LINE_NUMBER',
'        --             AND A.VC_MIGO_STATUS = ''P''), 0)',
'        --     ),',
'        --     ROUND(',
'        --         CASE ',
'        --             WHEN "Purchasing Doc. Type" IN (''ZSCO'', ''ZSFG'') THEN Document_Total_Net_Price',
'        --             ELSE TO_NUMBER("Net Price") / ',
'        --                  CASE WHEN NVL(TO_NUMBER("Price unit"), 0) = 0 THEN 1 ',
'        --                       ELSE TO_NUMBER("Price unit") END',
'        --         END, 2)',
'        -- INTO V_QTY, V_RATE',
'        -- FROM EBIZAI.VW_PURCHASE_DOC_TOTALS',
'        -- WHERE "Purchasing Document" = NVL(:P4_PO_NUMBER1, ''***'')',
'        --   AND TRIM("Material") = TRIM(:P4_SAP_ITEM_CODE1)',
'        --   AND "Item" = :P4_LINE_NUMBER;',
'',
'        SELECT ',
'  (',
'    a."Still to be delivered (qty)" - ',
'    NVL((',
'      SELECT sum(B.NU_QUANTITY)',
'      FROM HD_INVOICE_APP A1, DT_INVOICE_APP B',
'      WHERE A1.NU_LOG_ID = B.NU_PI_LOGID',
'        AND B.VC_PO_NUMBER = :P4_PO_NUMBER1',
'        AND TRIM(B.VC_SAP_ITEM_CODE) = TRIM(:P4_SAP_ITEM_CODE1)',
'        AND B.VC_LINE_NUMBER = :P4_LINE_NUMBER',
'        AND A1.VC_MIGO_STATUS = ''P''',
'    ), 0)',
'  ) AS ADJUSTED_DELIVERY_QTY,',
'  ROUND(',
'    CASE ',
'      WHEN a."Purchasing Doc. Type" IN (''ZSCO'', ''ZSFG'') THEN Document_Total_Net_Price',
'      WHEN B.vc_vendor_name IS NOT NULL THEN TO_NUMBER(a."Net Price")',
'      ELSE ',
'        TO_NUMBER(a."Net Price") / ',
'        CASE ',
'          WHEN NVL(TO_NUMBER(a."Price unit"), 0) = 0 THEN 1 ',
'          ELSE TO_NUMBER(a."Price unit") ',
'        END ',
'    END, ',
'    2',
'  )INTO V_QTY,V_RATE',
'  ',
'FROM EBIZAI.VW_PURCHASE_DOC_TOTALS1 A ',
'LEFT JOIN RATE_EXCEPTION B ',
'  ON TRIM(SUBSTR(a."Supplier/Supplying Plant", 7)) = UPPER(B.vc_vendor_name)',
'WHERE a."Purchasing Document" = NVL(:P4_PO_NUMBER1, ''***'')',
'  AND TRIM(a."Material") = TRIM(:P4_SAP_ITEM_CODE1)',
'  AND a."Item" =:P4_LINE_NUMBER;',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            v_error_msg := ''NO_DATA'';',
'    END;',
'',
'    -- Check PO status',
'    BEGIN',
'        SELECT CASE WHEN COUNT(*) > 0 THEN ''YES'' ELSE ''NO'' END ',
'        INTO v_po_status',
'        FROM EBIZAI.vw_sap_pending_po_vendor_gst',
'        WHERE VC_PO_NUMBER = :P4_PO_NUMBER1',
'          AND vc_gst_no = :P4_VENDOR_GST_IN',
'          AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            v_po_status := ''NO'';',
'    END;',
'',
'    -- Additional validations',
'    IF :P4_QUANTITY IS NULL THEN',
'        v_error_msg := ''Quantity_NOT_NULL'';',
'    ELSIF V_QTY < :P4_QUANTITY THEN',
'        v_error_msg := ''QUANTITY_EXCEEDED'';',
'    ELSIF :P4_RATE IS NULL THEN',
'        v_error_msg := ''RATE_NOT_NULL'';',
'    ELSIF V_RATE <> :P4_RATE THEN',
'        v_error_msg := ''RATE_MISMATCH'';',
'    ELSIF :P4_VC_STORAGE_LOCATION IS NULL THEN',
'        v_error_msg:=''STORAGE_LOCATION''; ',
'    END IF;',
'',
'    -- Always update the collection',
'    APEX_COLLECTION.UPDATE_MEMBER(',
'        P_COLLECTION_NAME => ''VENDOR_DT'',',
'        P_SEQ             => :P4_SEQ_ID,',
'        P_C001            => :P4_ITEM_DESCRIPTION,',
'        P_C005            => :P4_SAP_ITEM_CODE1,',
'        P_C003            => :P4_HSN_CODE,',
'        P_C004            => :P4_UNIT,',
'        P_N003            => :P4_QUANTITY,',
'        P_N004            => :P4_RATE,',
'        P_C011            => :P4_LINE_NUMBER,',
'        P_C050            => :GLOBAL_DOC_NO,',
'        P_C008            => :P4_ACTUAL_QTY,',
'        P_C010            => :P4_PO_NUMBER1,',
'        P_D001            => :P4_PO_DATE1,',
'        P_N001            => :P4_SAP_RATE,',
'        P_N002            => :P4_SAP_ITEM_RATE,',
'        P_C012            => v_po_status,',
'        P_C013            =>:P4_VC_HEAT_NO1,',
'        P_C014            =>:P4_VC_MILL_NAME1,',
'        P_C015            =>:P4_VC_MILL_COUNTRY,',
'        P_C016            =>:P4_VC_STORAGE_LOCATION',
'    );',
'',
'    -- Respond with appropriate message',
'    IF v_error_msg IS NOT NULL THEN',
'        htp.p(v_error_msg);',
'    ELSE',
'        htp.p(''SUCCESS'');',
'    END IF;',
'END;',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>68362221017765754
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(73592377835159631)
,p_process_sequence=>50
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'VALIDATIONS'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'------------------------Developed by Kunal Agarwal ---------------------------------------------',
'---------last updated on 04/04/2025----------------------------------------------------------',
'DECLARE',
'    v_exists NUMBER;',
'BEGIN',
'    -- :P4_ERROR_MESSAGE:= NULL;',
'    -- Check if PO Number exists',
'    SELECT COUNT(*) INTO v_exists FROM  sap_pending_po_tbl WHERE vc_po_number = :P4_PO_NUMBER1;',
'    -- AND TO_DATE(DT_PO_DATE, ''MM-DD-YYYY'') = TO_DATE(:P4_PO_DATE1, ''MM-DD-YYYY'');',
'',
'    ',
'    -- If PO Number does not exist, store message in a hidden item',
'    IF v_exists = 0 THEN',
'        HTP.P(''PO_NO_CHECK'');',
'        RETURN;',
'    END IF;',
'END;',
'',
'',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>73592377835159631
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(7025983088303289)
,p_process_sequence=>60
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'DELETE_MENU'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'------------------------Developed by Kunal Agarwal ---------------------------------------------',
'---------last updated on 28/03/2025----------------------------------------------------------',
'',
'DECLARE',
'    V_SEQ NUMBER := apex_application.g_x01;',
'BEGIN',
'    -- If V_SEQ is provided, delete from the collection',
'    IF V_SEQ IS NOT NULL THEN',
'        APEX_COLLECTION.DELETE_MEMBER(',
'            P_COLLECTION_NAME => ''VENDOR_DT'',',
'            P_SEQ => V_SEQ',
'        );',
'    END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>7025983088303289
);
end;
