wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(11830023795084589)
,p_plug_name=>'Pendency Report'
,p_region_template_options=>'#DEFAULT#:t-Region--accent1:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(314073806324267132)
,p_plug_display_sequence=>10
,p_include_in_reg_disp_sel_yn=>'Y'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'TO_CHAR(T2.DT_SCAN_DATE,''MON-YY'') "Scan Month",',
'T2.VC_VENDOR_NAME "Supplier",',
'COUNT(DISTINCT T1.NU_PI_LOGID) "Scan Invoices",',
'COUNT(DISTINCT CASE WHEN T2.CH_STATUS=''P''and  T2.VC_HOLD_REASON  IS  NULL THEN T1.NU_PI_LOGID ELSE NULL END) "Pending Invoices",',
'COUNT(DISTINCT CASE WHEN T2.CH_STATUS=''C'' THEN T1.NU_PI_LOGID ELSE NULL END) "Approved Invoices",',
'COUNT(DISTINCT CASE WHEN T2.CH_STATUS=''R'' THEN T1.NU_PI_LOGID ELSE NULL END) "Rejected Invoices",',
'COUNT(DISTINCT CASE WHEN T2.CH_STATUS=''P'' and  T2.VC_HOLD_REASON  IS NOT NULL  THEN T1.NU_PI_LOGID ELSE NULL END) "Hold Invoices",',
'COUNT(DISTINCT CASE WHEN NVL(T2.CH_STATUS,''NA'')=''C'' AND  ',
'(VC_MIGO_101 IS NULL AND VC_MIGO_103 IS NULL AND VC_MIGO_105 IS NULL AND VC_MIGO_STATUS=''P'')',
'THEN T1.NU_PI_LOGID ELSE NULL END) "Pending for MIGO",',
'COUNT(DISTINCT CASE WHEN (T3.VC_REMARK LIKE ''%MIGO DONE BY BOT%'' AND T3.VC_MIGO_STATUS=''C'')',
'THEN T1.NU_PI_LOGID  END) AS "MIGO DONE",',
' ',
'COUNT(DISTINCT CASE WHEN (T3.VC_REMARK NOT LIKE ''%MIGO DONE BY BOT%'' AND T3.VC_MIGO_STATUS=''F'')',
'THEN T1.NU_PI_LOGID END) AS "MIGO FAIL",',
' ',
'COUNT(DISTINCT CASE WHEN (T3.VC_MIGO_STATUS=''C'' AND T3.VC_REMARK LIKE ''%MIGO DONE BY BOT%''',
'AND (T3.VC_MIGO_101 IS NOT NULL OR T3.VC_MIGO_105 IS NOT NULL) AND T3.VC_MIRO_INVOICE_NO IS NULL)',
'THEN T1.NU_PI_LOGID END) AS "MIRO PENDING",',
' ',
'COUNT(DISTINCT CASE WHEN LENGTH(T3.VC_MIRO_INVOICE_NO)=10 AND T3.VC_MIRO_INVOICE_NO IS NOT NULL THEN T1.NU_PI_LOGID END) AS "MIRO DONE",',
' ',
'COUNT(DISTINCT CASE WHEN LENGTH(T3.VC_MIRO_INVOICE_NO)<>10 AND T3.VC_MIRO_INVOICE_NO IS NOT NULL ',
'THEN T1.NU_PI_LOGID END) AS "MIRO ERROR"',
' ',
'FROM vi_dt_vendor_inv T1',
'JOIN vi_hd_vendor_inv T2',
'ON T1.NU_PI_LOGID=T2.NU_LOG_ID',
'LEFT JOIN HD_INVOICE_APP T3',
'ON T1.NU_PI_LOGID=T3.NU_LOG_ID',
'--WHERE TO_CHAR(T2.DT_SCAN_DATE,''MON-YY'')=''JUL-25''',
'GROUP BY TO_CHAR(T2.DT_SCAN_DATE,''MON-YY''),T2.VC_VENDOR_NAME',
'ORDER BY T2.VC_VENDOR_NAME,TO_CHAR(T2.DT_SCAN_DATE,''MON-YY'')',
'--and "Hold Invoices" is not null'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_units=>'INCHES'
,p_prn_paper_size=>'LETTER'
,p_prn_width=>11
,p_prn_height=>8.5
,p_prn_orientation=>'HORIZONTAL'
,p_prn_page_header=>'Pendency Report'
,p_prn_page_header_font_color=>'#000000'
,p_prn_page_header_font_family=>'Helvetica'
,p_prn_page_header_font_weight=>'normal'
,p_prn_page_header_font_size=>'12'
,p_prn_page_footer_font_color=>'#000000'
,p_prn_page_footer_font_family=>'Helvetica'
,p_prn_page_footer_font_weight=>'normal'
,p_prn_page_footer_font_size=>'12'
,p_prn_header_bg_color=>'#EEEEEE'
,p_prn_header_font_color=>'#000000'
,p_prn_header_font_family=>'Helvetica'
,p_prn_header_font_weight=>'bold'
,p_prn_header_font_size=>'10'
,p_prn_body_bg_color=>'#FFFFFF'
,p_prn_body_font_color=>'#000000'
,p_prn_body_font_family=>'Helvetica'
,p_prn_body_font_weight=>'normal'
,p_prn_body_font_size=>'10'
,p_prn_border_width=>.5
,p_prn_page_header_alignment=>'CENTER'
,p_prn_page_footer_alignment=>'CENTER'
,p_prn_border_color=>'#666666'
);
