,p_html_page_header=>wwv_flow_string.join(wwv_flow_t_varchar2(
'<div id="customConfirm" style="display:none; position:fixed; top:50%; left:50%; transform:translate(-50%, -50%); background:#fff; border:1px solid #ccc; padding:20px; z-index:1000;">',
'    <p id="confirmMessage"></p>',
'    <div style="display: flex; justify-content: space-between;">',
'        <button id="confirmCancel" style="background-color: #dc3545; color: white; border: none; padding: 5px 10px; font-size: 14px; cursor: pointer; border-radius: 5px;">Cancel</button>',
'        <button id="confirmOk" style="background-color: #28a745; color: white; border: none; padding: 5px 10px; font-size: 14px; cursor: pointer; border-radius: 5px;">OK</button>',
'    </div>',
'</div>',
'<div id="overlay" style="display:none; position:fixed; top:0; left:0; width:100%; height:100%; background:rgba(0,0,0,0.5); z-index:999;"></div>',
''))
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'// var htmldb_delete_message=''"DELETE_CONFIRM_MSG"'';',
'// var htmldb_ch_message=''"OK_TO_GET_NEXT_PREV_PK_VALUE"'';',
'',
'// var htmldb_delete_message=''"DELETE_CONFIRM_MSG"'';',
'// var htmldb_ch_message=''"OK_TO_GET_NEXT_PREV_PK_VALUE"'';',
'',
'',
'',
'function JS_ADD_MENU() {',
'    apex.server.process(',
'        "ADD MENU",',
'        {',
'            pageItems: "#P18_VC_ROLE_NAME, #P18_MENU_LIST"',
'        },',
'        {',
'            dataType: ''text'',',
'            success: function(pData) {',
'                // Trim whitespace from the response data',
'                var response = $.trim(pData);',
'',
'                // Handle different responses from PL/SQL block',
'                switch(response) {',
'                    case ''N'':',
'                        apex.message.alert(''Item cannot be null !!!'');',
'                        break;',
'                    default:',
'                        // If insertion is successful, refresh the report',
'                        apex.region("REF").refresh();',
'                        break;',
'                }',
'            },',
'            error: function(jqXHR, textStatus, errorThrown) {',
'                // Handle any server-side errors',
'                apex.message.alert(''Server error: '' + textStatus + '' - '' + errorThrown);',
'            }',
'        }',
'    );',
'}',
'',
'',
'',
'',
'',
'',
'',
'function js_del_menu(v_seq) {',
'    // Set the message in the dialog',
'    document.getElementById(''confirmMessage'').innerText = "Are you sure you want to delete the row no: " + v_seq +  "?";',
'    ',
'    // Show the dialog and overlay',
'    document.getElementById(''customConfirm'').style.display = ''block'';',
'    document.getElementById(''overlay'').style.display = ''block'';',
'',
'    // Handle the OK button click',
'    document.getElementById(''confirmOk'').onclick = function() {',
'        // Hide the dialog',
'        document.getElementById(''customConfirm'').style.display = ''none'';',
'        document.getElementById(''overlay'').style.display = ''none'';',
'',
'        // Call the server process to delete the task',
'        apex.server.process("DELETE  MENU", {',
'            pageItems: "#P18_VC_ROLE_NAME, #P18_MENU_LIST",',
'            x01: v_seq',
'        }, {',
'            type: ''GET'',',
'            dataType: ''text'',',
'            success: function(data) {',
'                apex.region("REF").refresh(); ',
'              ///  apex.region("COURSE_DETAILS").refresh();  ',
'            }',
'        });',
'    };',
'',
'    // Handle the Cancel button click',
'    document.getElementById(''confirmCancel'').onclick = function() {',
'        // Hide the dialog and overlay',
'        document.getElementById(''customConfirm'').style.display = ''none'';',
'        document.getElementById(''overlay'').style.display = ''none'';',
'    };',
'}',
''))
,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
