wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(70910348750972144)
,p_process_sequence=>30
,p_process_point=>'AFTER_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'GET DATA'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'   l_collection_name VARCHAR2(100) := ''TEMP_ROLE_MENU'';',
'BEGIN',
'   -- Check if collection exists; create if not',
'   IF NOT apex_collection.collection_exists(l_collection_name) THEN',
'      apex_collection.create_collection(p_collection_name => l_collection_name);',
'   ELSE',
'      -- Clear collection before inserting new values',
'      apex_collection.truncate_collection(p_collection_name => l_collection_name);',
'   END IF;',
'',
'   -- Insert filtered data into collection',
'   FOR rec IN (',
'      SELECT M.VC_MENU_CODE, M.VC_MENU_NAME ',
'      FROM MST_MODULE_MENU M',
'      JOIN MST_MENU_BASKET B ',
'          ON M.VC_MENU_CODE = B.VC_MENU_CODE',
'      WHERE B.VC_COMP_CODE = :P18_COMP_CODE1',
'      AND B.VC_ROLE_CODE = :P18_ROLE_CODE1',
'   ) LOOP',
'      APEX_COLLECTION.ADD_MEMBER(',
'         p_collection_name => l_collection_name,',
'         p_c001 => rec.VC_MENU_CODE,  ',
'         p_c002 => rec.VC_MENU_NAME   ',
'      );',
'   END LOOP;',
'END;',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>70910348750972144
);
wwv_flow_imp_page.create_page_process(
