wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(70909989619972140)
,p_process_sequence=>40
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'SAVE'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'   V_NEW_ID NUMBER;',
'   V_COUNT  NUMBER;',
'   ',
'   -- Cursor for menus stored in the collection',
'   CURSOR cur_menu IS ',
'      SELECT C001 AS MENU_CODE ',
'      FROM APEX_COLLECTIONS ',
'      WHERE COLLECTION_NAME = ''TEMP_ROLE_MENU'';',
'',
'BEGIN',
'   -- Step 1: Generate new Role ID if it does not exist',
'   BEGIN',
'      SELECT VC_ROLE_CODE ',
'      INTO V_NEW_ID',
'      FROM MST_ROLE',
'      WHERE VC_ROLE_NAME = :P18_VC_ROLE_NAME',
'      AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'   EXCEPTION',
'      WHEN NO_DATA_FOUND THEN',
'         -- If Role does not exist, create a new one',
'         SELECT NVL(MAX(TO_NUMBER(VC_ROLE_CODE)), 0) + 1',
'         INTO V_NEW_ID',
'         FROM MST_ROLE;',
'         ',
'         INSERT INTO MST_ROLE (VC_COMP_CODE, VC_ROLE_CODE, VC_ROLE_NAME, DT_CRT_DATE)',
'         VALUES (:GLOBAL_COMP_CODE, V_NEW_ID, :P18_VC_ROLE_NAME, SYSDATE);',
'   END;',
'',
'   -- Step 2: DELETE records from MST_MENU_BASKET that are NOT in the collection',
'   FOR db_rec IN (',
'      SELECT VC_MENU_CODE ',
'      FROM MST_MENU_BASKET ',
'      WHERE VC_ROLE_CODE = V_NEW_ID',
'      AND VC_COMP_CODE = :GLOBAL_COMP_CODE',
'   ) LOOP',
'      SELECT COUNT(*) ',
'      INTO V_COUNT ',
'      FROM APEX_COLLECTIONS ',
'      WHERE COLLECTION_NAME = ''TEMP_ROLE_MENU'' ',
'      AND C001 = db_rec.VC_MENU_CODE;',
'',
'      IF V_COUNT = 0 THEN',
'         DELETE FROM MST_MENU_BASKET',
'         WHERE VC_MENU_CODE = db_rec.VC_MENU_CODE',
'         AND VC_ROLE_CODE = V_NEW_ID',
'         AND VC_COMP_CODE = :GLOBAL_COMP_CODE;',
'      END IF;',
'   END LOOP;',
'',
'   -- Step 3: INSERT or UPDATE records based on existence',
'   FOR rec IN cur_menu LOOP',
'      -- Check if the menu already exists for the role',
'      SELECT COUNT(*) INTO V_COUNT ',
'      FROM MST_MENU_BASKET ',
'      WHERE VC_COMP_CODE = :GLOBAL_COMP_CODE ',
'      AND VC_ROLE_CODE = V_NEW_ID ',
'      AND VC_MENU_CODE = rec.MENU_CODE;',
'',
'      IF V_COUNT > 0 THEN',
'         -- If exists, update it',
'         UPDATE MST_MENU_BASKET',
'         SET DT_MOD_DATE = SYSDATE, CH_ADD = ''Y'', CH_MOD = ''Y'', CH_DEL = ''Y''',
'         WHERE VC_COMP_CODE = :GLOBAL_COMP_CODE ',
'         AND VC_ROLE_CODE = V_NEW_ID ',
'         AND VC_MENU_CODE = rec.MENU_CODE;',
'      ELSE',
'         -- If not, insert a new record',
'         INSERT INTO MST_MENU_BASKET(',
'            VC_COMP_CODE, VC_ROLE_CODE, VC_MENU_CODE, DT_CRT_DATE, DT_MOD_DATE, CH_ADD, CH_MOD, CH_DEL) ',
'            VALUES (:GLOBAL_COMP_CODE, V_NEW_ID, rec.MENU_CODE, SYSDATE, SYSDATE, ''Y'', ''Y'', ''Y'');',
'      END IF;',
'   END LOOP;',
'END;',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(70911042695972151)
,p_internal_uid=>70909989619972140
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(70909756548972138)
,p_process_sequence=>10
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'ADD MENU'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'   l_collection_name VARCHAR2(100) := ''TEMP_ROLE_MENU'';',
'   l_exists          BOOLEAN := FALSE;',
'BEGIN',
'   -- Check if collection exists, then create if it doesn''t',
'   IF NOT apex_collection.collection_exists(l_collection_name) THEN',
'      apex_collection.create_collection(p_collection_name => l_collection_name);',
'   END IF;',
'',
'   -- Check if the value already exists in the collection',
'   FOR rec IN (SELECT 1 FROM APEX_COLLECTIONS ',
'               WHERE COLLECTION_NAME = l_collection_name ',
'               AND C001 = :P18_MENU_LIST) ',
'   LOOP',
'      l_exists := TRUE;',
'   END LOOP;',
